import http from 'node:http';
import { randomUUID } from 'node:crypto';

function createApp(){
  const routes=[];
  const addRoute=(method,path,handler)=>routes.push({method,path,handler});
  const matchRoute=(routePath,pathname)=>{
    if(routePath==='*')return{};
    if(routePath===pathname)return{};
    const routeParts=routePath.split('/').filter(Boolean);
    const pathParts=pathname.split('/').filter(Boolean);
    if(routeParts.length!==pathParts.length)return null;
    const params={};
    for(let i=0;i<routeParts.length;i++){
      const r=routeParts[i],p=pathParts[i];
      if(r.startsWith(':'))params[r.slice(1)]=decodeURIComponent(p);
      else if(r!==p)return null;
    }
    return params;
  };
  const enhanceRes=res=>{
    res.status=function(code){res.statusCode=code;return res;};
    res.json=function(data){
      if(!res.headersSent)res.setHeader('Content-Type','application/json; charset=utf-8');
      res.end(JSON.stringify(data));
    };
    res.send=function(data){
      if(!res.headersSent&&!res.getHeader('Content-Type'))res.setHeader('Content-Type','text/html; charset=utf-8');
      res.end(data);
    };
  };
  const readBody=req=>new Promise(resolve=>{
    let body='';
    req.on('data',chunk=>{body+=chunk;});
    req.on('end',()=>{
      if(!body){req.body={};resolve();return;}
      try{req.body=JSON.parse(body);}catch(_){req.body={};}
      resolve();
    });
    req.on('error',()=>{req.body={};resolve();});
  });
  return{
    use(){},
    get(path,handler){addRoute('GET',path,handler);},
    post(path,handler){addRoute('POST',path,handler);},
    listen(port,host,cb){
      const server=http.createServer(async(req,res)=>{
        enhanceRes(res);
        const pathname=new URL(req.url,'http://localhost').pathname;
        let route=null,params=null;
        for(const r of routes){
          if(r.method!==req.method)continue;
          const match=matchRoute(r.path,pathname);
          if(match){route=r;params=match;break;}
        }
        if(!route){res.status(404).json({error:'Not found'});return;}
        req.params=params||{};
        if(req.method==='POST')await readBody(req);
        try{await route.handler(req,res);}catch(e){
          if(!res.writableEnded)res.status(500).json({error:e.message||'Internal server error'});
        }
      });
      return server.listen(port,host,cb);
    }
  };
}

const app=createApp();

