const STATIC_Q = [{"q":"What does GDP measure?","o":["Total value of final goods and services produced in a country in a given period","Total value of all transactions including intermediate goods","Total income earned by a country's citizens worldwide","Total government and private investment"],"a":0,"e":"GDP measures the monetary value of final goods and services produced within a country's borders. It excludes intermediate goods to avoid double-counting. The three approaches (expenditure, income, output) yield identical results.","cat":"MACRO","diff":"ANALYST","mod":"GDP","concept":"GDP definition"},{"q":"Which GDP component is typically largest in developed economies?","o":["Government spending","Gross private investment","Net exports","Private consumption"],"a":3,"e":"Private consumption (household spending) typically accounts for 60-70% of GDP in developed economies. In the US it represents approximately 70% of GDP, making consumer confidence a critical macro indicator.","cat":"MACRO","diff":"ANALYST","mod":"GDP","concept":"GDP components"},{"q":"If nominal GDP grows 6% and inflation is 4%, what is real GDP growth?","o":["10%","2%","4%","6%"],"a":1,"e":"Real GDP growth approximates nominal GDP growth minus inflation: 6% - 4% = 2%. Real GDP strips out price changes to isolate actual output growth, the true measure of economic expansion.","cat":"MACRO","diff":"ANALYST","mod":"GDP","concept":"Real vs nominal GDP"},{"q":"What is the output gap?","o":["Difference between imports and exports","Difference between actual GDP and potential GDP","Difference between nominal and real GDP","Difference between GDP and GNP"],"a":1,"e":"The output gap measures actual GDP minus potential GDP (full-capacity output). A negative gap signals spare capacity and disinflationary pressure; a positive gap signals overheating and inflationary pressure. Central banks monitor it closely.","cat":"MACRO","diff":"VP","mod":"GDP","concept":"Output gap"},{"q":"What does the Keynesian multiplier predict?","o":["Money supply increases multiply through fractional reserve banking","Government spending increases output by more than the initial amount","Tax cuts have a larger GDP impact than equivalent spending increases","Inflation multiplies through wage-price spirals"],"a":1,"e":"The Keynesian multiplier: an initial increase in government spending generates a larger total increase in GDP as recipients re-spend income in a chain. The multiplier size depends on the marginal propensity to consume and import leakage.","cat":"MACRO","diff":"VP","mod":"GDP","concept":"Fiscal multiplier"},{"q":"What is stagflation?","o":["High inflation combined with high economic growth","High inflation combined with stagnant growth and high unemployment","Deflation combined with rapid growth","Stable inflation combined with low unemployment"],"a":1,"e":"Stagflation \u2014 stagnant growth plus inflation \u2014 is the central banker's nightmare. Tightening to fight inflation worsens unemployment; easing to support growth worsens inflation. The 1970s oil shocks created the defining stagflation episode.","cat":"MACRO","diff":"ANALYST","mod":"Inflation","concept":"Stagflation"},{"q":"What is the difference between CPI and PCE inflation?","o":["CPI measures wholesale prices; PCE consumer prices","PCE uses a fixed basket; CPI adjusts for substitution","CPI uses a fixed basket; PCE adjusts for substitution and covers a broader range of goods","They measure identical things calculated differently"],"a":2,"e":"CPI uses a fixed basket, overstating inflation when consumers substitute cheaper alternatives. PCE adjusts for substitution bias and covers a broader expenditure range. The Fed targets Core PCE because it better reflects actual consumer behaviour.","cat":"MACRO","diff":"VP","mod":"Inflation","concept":"CPI vs PCE"},{"q":"What is core inflation?","o":["Inflation excluding energy only","Inflation excluding food and energy","Inflation in manufacturing only","Inflation adjusted for wages"],"a":1,"e":"Core inflation excludes food and energy, which are volatile and driven by supply shocks outside monetary policy control. Central banks focus on core to assess underlying demand-driven price pressures rather than transitory supply disruptions.","cat":"MACRO","diff":"ANALYST","mod":"Inflation","concept":"Core inflation"},{"q":"What is the Fisher effect?","o":["Real rates equal nominal rates minus inflation","Nominal rates adjust one-for-one with expected inflation, keeping real rates stable","Higher inflation always causes currency depreciation","Central banks control real but not nominal rates"],"a":1,"e":"The Fisher effect: nominal interest rates adjust to reflect expected inflation, leaving real rates unchanged in the long run. If expected inflation rises 1%, nominal rates rise ~1%. This explains why high-inflation countries have high nominal rates.","cat":"MACRO","diff":"VP","mod":"Inflation","concept":"Fisher effect"},{"q":"Which measure of inflation does the Fed officially target?","o":["CPI","Core CPI","PCE","Core PCE"],"a":3,"e":"The Fed officially targets Core PCE at 2%. Core PCE is preferred over CPI because it adjusts for consumer substitution behaviour and covers a broader range of spending patterns.","cat":"MACRO","diff":"ANALYST","mod":"Inflation","concept":"Fed inflation target"},{"q":"What is the Phillips Curve?","o":["Relationship between inflation and interest rates","Historical inverse relationship between inflation and unemployment","Relationship between GDP growth and inflation","Relationship between money supply and inflation"],"a":1,"e":"The Phillips Curve describes an empirical inverse relationship between inflation and unemployment. Low unemployment correlates with higher wage pressure and inflation. The relationship weakened in the 2010s when unemployment fell without triggering inflation.","cat":"MACRO","diff":"VP","mod":"Inflation","concept":"Phillips Curve"},{"q":"What is deflation and why do central banks fear it?","o":["Falling asset prices \u2014 feared because it reduces wealth","General fall in price levels \u2014 feared because it can trigger a debt-deflation spiral trapping economies in recession","Fall in government bond prices","Fall in currency value increasing import costs"],"a":1,"e":"Deflation creates a debt-deflation spiral: consumers delay purchases expecting lower prices, demand falls, prices fall further, real debt burdens rise, defaults increase. Japan's lost decades after 1990 are the defining example. Central banks treat deflation risk with extreme seriousness.","cat":"MACRO","diff":"VP","mod":"Inflation","concept":"Deflation risk"},{"q":"What is quantitative easing (QE)?","o":["Directly depositing money into household bank accounts","Central bank purchasing assets (usually bonds) from banks, increasing reserves and reducing long-term yields","Lowering reserve requirements to allow more lending","Printing physical currency and distributing through banks"],"a":1,"e":"QE: the central bank buys assets (typically government bonds) from commercial banks, crediting their reserve accounts. This increases bank reserves, reduces bond supply (pushing yields down), and aims to lower borrowing costs across the economy and encourage risk-taking.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"QE mechanics"},{"q":"What is forward guidance in monetary policy?","o":["Central bank communication about future rate intentions to influence current conditions","A central bank forecast of future GDP growth","Process of setting rates based on inflation projections","IMF guidance to developing countries on monetary policy"],"a":0,"e":"Forward guidance: central banks communicate future policy intentions to influence current expectations and financial conditions. By signaling rates will stay low 'for longer', a central bank can lower long-term yields without actually cutting rates. It became a major tool after rates hit zero post-2008.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"Forward guidance"},{"q":"What is the zero lower bound problem?","o":["Central banks cannot legally set negative rates","Rate cuts lose effectiveness near zero because nominal rates cannot easily go below zero","Economic growth cannot fall below zero","Bond yields cannot fall below zero"],"a":1,"e":"The ZLB: nominal interest rates cannot easily fall below zero, limiting conventional monetary policy. It prompted unconventional tools: QE, forward guidance, yield curve control, and negative rates. Japan and the Eurozone pushed into negative territory to escape the ZLB.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"Zero lower bound"},{"q":"What is the neutral rate of interest (r-star)?","o":["The rate at which inflation equals zero","The real rate consistent with full employment and stable inflation \u2014 neither stimulative nor restrictive","The rate at which bond yields equal inflation","The Fed Funds rate averaged over a full cycle"],"a":1,"e":"R-star is the unobservable real rate that neither stimulates nor restricts the economy at full employment with stable inflation. Policy above r-star is restrictive; below is accommodative. Estimates of r-star have declined significantly since the 1980s due to demographic and structural shifts.","cat":"MACRO","diff":"MD","mod":"Monetary policy","concept":"Neutral rate"},{"q":"What are automatic stabilisers?","o":["Government rules preventing deficits exceeding 3% of GDP","Spending and tax mechanisms that automatically cushion downturns without new legislation","Central bank tools that automatically respond to economic conditions","Trade tariffs that automatically adjust to exchange rates"],"a":1,"e":"Automatic stabilisers expand spending (unemployment benefits, welfare) or reduce tax collection automatically during downturns, cushioning demand without legislative action. They contract automatically during booms. Key difference from discretionary fiscal policy: no implementation lag.","cat":"MACRO","diff":"VP","mod":"Fiscal policy","concept":"Automatic stabilisers"},{"q":"What is 'crowding out' in fiscal policy?","o":["Government spending directly replacing private sector activity","Higher government borrowing raises interest rates, reducing private investment","Tax increases reducing consumer spending","Government regulation preventing private sector entry"],"a":1,"e":"Crowding out: government borrowing increases demand for loanable funds, pushing up interest rates, reducing private sector investment. Crowding out is stronger when the economy is near full capacity and weaker during recessions when private demand is low.","cat":"MACRO","diff":"VP","mod":"Fiscal policy","concept":"Crowding out"},{"q":"What is the liquidity trap?","o":["When banks refuse to lend to each other","When interest rates hit zero and further cuts lose effectiveness as people hoard cash","When excess money supply creates runaway inflation","When central bank reserves become too large for open market operations"],"a":1,"e":"A liquidity trap: nominal rates hit zero and monetary policy loses traction. People hold cash rather than invest (expecting deflation or low returns), banks hoard reserves rather than lend. Japan in the 1990s-2000s is the defining example, informing the design of QE.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"Liquidity trap"},{"q":"What is the NAIRU?","o":["Non-Accelerating Asset Return Unemployment Rate","Non-Accelerating Inflation Rate of Unemployment \u2014 unemployment consistent with stable inflation","Natural Annual Increase in Real Unemployment","National Average Income Rate of Unemployment"],"a":1,"e":"NAIRU: the unemployment level consistent with stable inflation. Below NAIRU, labour markets are tight and wages accelerate, pushing inflation higher. Above NAIRU, there is slack and inflation tends to fall. It is unobservable and changes over time.","cat":"MACRO","diff":"VP","mod":"Labor markets","concept":"NAIRU"},{"q":"What is the participation rate?","o":["Percentage of working-age people employed or actively seeking work \u2014 a fall can mask true unemployment","Percentage of GDP contributed by the labour force","Rate at which workers switch jobs","Proportion of wages relative to GDP"],"a":0,"e":"The participation rate measures the share of working-age adults who are employed or actively looking. When discouraged workers stop looking, unemployment falls without genuine improvement. This is why headline unemployment can be misleading as a sole labour market indicator.","cat":"MACRO","diff":"VP","mod":"Labor markets","concept":"Participation rate"},{"q":"What is secular stagnation?","o":["A temporary slowdown caused by demographic ageing","Structural tendency for developed economies to have weak growth and very low rates due to persistent excess savings over investment \u2014 Larry Summers' thesis","A period of stagflation lasting more than one cycle","The tendency for EM to grow more slowly than developed markets"],"a":1,"e":"Secular stagnation (Summers, 2013): persistent excess of savings over desired investment keeps real neutral rates chronically low. Causes: ageing demographics, falling investment needs in the digital economy, rising inequality. Implications: frequent ZLB encounters, need for fiscal stimulus.","cat":"MACRO","diff":"MD","mod":"GDP","concept":"Secular stagnation"},{"q":"What is Modern Monetary Theory (MMT)?","o":["Central banks should directly target employment rather than inflation","Governments issuing their own currency can never truly default and should spend until full employment, using taxation to control inflation","Money supply growth should equal nominal GDP growth","A framework for analysing central bank digital currencies"],"a":1,"e":"MMT: sovereign currency issuers cannot default on domestic currency debt; deficits create money; the constraint on spending is inflation not solvency; taxes reduce demand rather than fund government. Critics argue it underestimates inflation risk and bond market discipline.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"Modern Monetary Theory"},{"q":"What is fiscal dominance?","o":["When the executive branch overrides central bank rate decisions","When government debt is so large the central bank is forced to keep rates low to prevent a debt crisis \u2014 subordinating monetary to fiscal needs","When fiscal policy becomes the primary economic stabilisation tool","When government spending exceeds 50% of GDP"],"a":1,"e":"Fiscal dominance: debt burden so large that raising rates risks a sovereign debt crisis, effectively constraining monetary policy. EM countries with high debt and weak institutions are most vulnerable. Some economists argue the US is approaching fiscal dominance given high debt and structural deficits.","cat":"MACRO","diff":"MD","mod":"Fiscal policy","concept":"Fiscal dominance"},{"q":"What is the paradox of thrift?","o":["Higher savings rates always lead to higher long-run growth","When all individuals simultaneously increase saving during recession, aggregate demand falls and the economy ends up poorer \u2014 making collective savings no higher at a lower income","Higher government saving always crowds out private saving","Countries with high savings always have current account surpluses"],"a":1,"e":"The paradox of thrift (Keynes): individually rational saving is collectively destructive in a recession. Each person cutting spending reduces someone else's income, who then cuts spending. The multiplied effect can leave the economy with the same savings at a lower income level. This justifies Keynesian stimulus during downturns.","cat":"MACRO","diff":"VP","mod":"Fiscal policy","concept":"Paradox of thrift"},{"q":"What does Covered Interest Rate Parity (CIP) state?","o":["Higher interest rate currencies always appreciate","Forward exchange rate should reflect interest rate differentials \u2014 eliminating risk-free arbitrage","Currencies of countries with higher inflation always depreciate","Central bank intervention can permanently fix exchange rates"],"a":1,"e":"CIP: the forward exchange rate premium/discount should exactly offset interest rate differentials between two currencies. If a currency offers a higher rate, it should trade at a forward discount by an equivalent amount \u2014 otherwise risk-free arbitrage profits would exist. CIP deviated significantly post-2008 due to dollar funding stress.","cat":"FX","diff":"VP","mod":"Interest rate parity","concept":"Covered Interest Rate Parity"},{"q":"What does Uncovered Interest Rate Parity (UIP) predict?","o":["Higher interest rate currencies will appreciate","Higher interest rate currencies will depreciate by the amount of the rate differential on average","Rate differentials have no effect on exchange rates","Forward rates are unbiased predictors of future spot rates"],"a":1,"e":"UIP predicts high-rate currencies depreciate by approximately the rate differential, leaving investors indifferent. In practice UIP consistently fails \u2014 high-rate currencies tend to appreciate rather than depreciate, which is the basis of the profitable carry trade.","cat":"FX","diff":"VP","mod":"Interest rate parity","concept":"Uncovered Interest Rate Parity"},{"q":"What is the carry trade?","o":["Trading currencies during high volatility","Borrowing in low-rate currencies and investing in high-rate currencies to earn the rate differential","Trading currency futures to hedge export revenues","Purchasing foreign bonds and hedging currency risk with forwards"],"a":1,"e":"The carry trade exploits UIP failure: borrow in a low-rate currency (historically JPY, CHF) and invest in a high-rate currency (AUD, NZD, EM). Profit is the interest rate differential ('carry'). Risk: sudden sharp reversals \u2014 'carry crashes' \u2014 when risk-off sentiment causes high-yielders to sell off sharply.","cat":"FX","diff":"VP","mod":"FX carry","concept":"Carry trade"},{"q":"Why does the carry trade tend to crash suddenly?","o":["Carry trades are regulated, requiring simultaneous exit when limits are exceeded","Carry trades are typically funded with short-term leverage; volatility spikes trigger margin calls forcing simultaneous unwinding","Carry traders all receive simultaneous algorithmic exit signals","Central banks coordinate to unwind carry positions during risk-off episodes"],"a":1,"e":"Carry trades are leveraged and crowded. When risk-off shocks hit, volatility spikes trigger margin calls across many investors simultaneously. The rush to unwind \u2014 selling high-yielders and buying the funding currency \u2014 creates sharp, self-reinforcing moves: the 'carry crash'.","cat":"FX","diff":"MD","mod":"FX carry","concept":"Carry crash mechanics"},{"q":"What is Purchasing Power Parity (PPP)?","o":["Exchange rates adjust so the same basket of goods costs the same in two countries","Countries with higher productivity grow faster","Central banks should target exchange rates to maintain competitiveness","Commodity-exporting currencies track commodity prices"],"a":0,"e":"PPP: exchange rates should equalise purchasing power \u2014 a basket of goods should cost the same across countries when converted at spot rate. Works as a long-run equilibrium concept but fails short-run due to capital flows, sentiment, and non-traded goods. The Big Mac Index is a famous PPP proxy.","cat":"FX","diff":"ANALYST","mod":"PPP","concept":"Purchasing Power Parity"},{"q":"What is the Impossible Trinity (Mundell-Fleming trilemma)?","o":["A country cannot simultaneously have free capital flows, a fixed exchange rate, and independent monetary policy","Countries cannot simultaneously achieve low inflation, low unemployment, and high growth","A central bank cannot simultaneously control inflation, unemployment, and the exchange rate","Financial stability, price stability, and full employment cannot all be achieved simultaneously"],"a":0,"e":"The Mundell-Fleming Trilemma: a country can have at most two of: (1) fixed exchange rate, (2) free capital movement, (3) independent monetary policy. The Eurozone chose 1+2. China chose 1+3 (capital controls). The US chose 2+3 (floating rate).","cat":"FX","diff":"VP","mod":"Exchange rate regimes","concept":"Impossible Trinity"},{"q":"What characterised the 1997 Asian currency crisis?","o":["Oil price collapse triggered sovereign defaults across Asia","Fixed exchange rate pegs to USD became unsustainable as current account deficits widened and speculative attacks broke the pegs","Federal Reserve rate hikes caused dollar appreciation crushing Asian currencies","Asian central banks raised rates too aggressively causing recession"],"a":1,"e":"Asian currencies (THB, IDR, MYR, KRW) were pegged to USD while running large current account deficits funded by short-term foreign borrowing. As the dollar strengthened, competitiveness eroded. George Soros attacked the Thai baht in July 1997; contagion spread across Asia.","cat":"FX","diff":"VP","mod":"Currency crises","concept":"Asian currency crisis 1997"},{"q":"What is sterilised FX intervention?","o":["Central bank FX purchases offset by domestic open market operations to neutralise the monetary impact","Central bank FX sales to defend an exchange rate floor","Government restrictions on foreign currency transactions","Central bank agreement with IMF to stabilise exchange rates"],"a":0,"e":"Sterilised intervention: a central bank buys/sells foreign currency but simultaneously conducts offsetting domestic operations (e.g. selling bonds) to keep the money supply unchanged. This allows managing the exchange rate without changing monetary conditions \u2014 though its long-run effectiveness is debated.","cat":"FX","diff":"MD","mod":"FX intervention","concept":"Sterilised intervention"},{"q":"What is the J-curve effect in trade?","o":["Trade deficits widen before improving after depreciation because import prices rise immediately while export volumes adjust slowly","Exchange rates follow a J-shaped path after central bank intervention","Current account surpluses always generate appreciation following a J-shaped trajectory","Trade balances improve immediately then stabilise after depreciation"],"a":0,"e":"After currency depreciation, the trade balance initially worsens before improving \u2014 the J-curve. Immediately post-depreciation, the same volumes are traded at higher prices (widening the value deficit). Over time, exporters gain competitiveness and import volumes fall, improving the balance.","cat":"FX","diff":"VP","mod":"FX mechanics","concept":"J-curve effect"},{"q":"What drove the SNB to impose a EUR/CHF floor of 1.20 in 2011?","o":["Inflationary pressures requiring a weaker franc","Safe-haven flows into CHF were causing severe appreciation, threatening Swiss exporters and risking deflation","A bilateral agreement with the ECB to support the euro","Concerns about excessive FX reserve accumulation"],"a":1,"e":"During the Eurozone crisis, risk-off flows drove massive safe-haven demand for CHF. EUR/CHF fell toward parity, devastating Swiss exporters and creating deflation risk. The SNB imposed a 1.20 floor in September 2011 with unlimited EUR purchases. It abandoned the floor in January 2015 \u2014 causing CHF to surge 30% in hours.","cat":"FX","diff":"VP","mod":"FX intervention","concept":"SNB floor 2011"},{"q":"What is the 'dollar smile' theory?","o":["USD tends to appreciate in both risk-on (strong US growth) and risk-off (safe haven) environments, but weakens when global growth is synchronised","USD depreciates during US recessions and appreciates during expansions in a predictable pattern","The dollar's value smiles when the Fed cuts rates","The USD tracks the US trade deficit in a smile-shaped pattern"],"a":0,"e":"Dollar smile: USD strengthens at both extremes \u2014 during US outperformance (strong growth attracts capital) and during global risk-off (safe haven demand). USD weakens in the middle scenario when global growth is strong and synchronised, reducing safe-haven demand and encouraging risk-seeking in higher-yielding assets.","cat":"FX","diff":"MD","mod":"FX mechanics","concept":"Dollar smile theory"},{"q":"What is a non-deliverable forward (NDF)?","o":["A forward contract where physical delivery is mandatory","A forward contract settling in USD rather than the non-convertible local currency \u2014 used for currencies with capital controls (CNY, INR, BRL)","A forward contract with no fixed maturity date","A swap where two parties exchange interest payments in different currencies"],"a":1,"e":"NDFs are forward contracts for currencies with capital controls. They settle in USD at the NDF rate vs the official fixing. CNY NDF can diverge from onshore CNY, providing a market signal of depreciation pressure. NDFs are widely used by corporations and investors managing EM currency exposure without direct market access.","cat":"FX","diff":"MD","mod":"FX mechanics","concept":"Non-deliverable forwards"},{"q":"What drives JPY's safe-haven status?","o":["Japan's large gold reserves backing the yen","Japan is the world's largest net creditor \u2014 Japanese investors repatriate overseas investments during crises, creating JPY demand; additionally JPY is the global carry trade funding currency","Japan's current account surplus guarantees yen stability","BOJ's credible inflation-fighting framework"],"a":1,"e":"JPY safe-haven mechanics: (1) Japan is the world's largest net creditor \u2014 $3tn+ in net foreign assets. During crises, Japanese investors repatriate, selling foreign assets and buying JPY. (2) JPY is the primary carry trade funding currency \u2014 when carry unwinds, investors buy back JPY. Both flows create systematic JPY appreciation during risk-off.","cat":"FX","diff":"VP","mod":"FX mechanics","concept":"JPY safe haven mechanics"},{"q":"What is FX implied volatility?","o":["The bid-ask spread on currency pairs, in basis points","Implied volatility from FX options prices \u2014 the market's expectation of future price variability, quoted as annualised standard deviation","The daily price range of a currency pair","The divergence between spot and forward exchange rates"],"a":1,"e":"FX implied vol is extracted from options prices \u2014 reflecting expected future variability. Quoted as annualised standard deviation (e.g. EUR/USD 1M vol at 6% implies ~1.7% monthly moves). Volatility spikes during risk-off events, central bank surprises, and geopolitical shocks.","cat":"FX","diff":"VP","mod":"FX vol","concept":"FX implied volatility"},{"q":"What is FX risk reversal?","o":["Cost of unwinding an existing FX forward position","Difference in implied vol between OTM calls and puts \u2014 indicating market directional bias","A central bank's decision to reverse its FX intervention stance","Converting FX gains back to domestic currency"],"a":1,"e":"Risk reversal measures options skew \u2014 the vol difference between OTM calls and puts. A positive risk reversal (calls more expensive than puts) signals bullish bias. Negative signals bearish bias. In USD/JPY, negative risk reversals reflect demand for JPY upside protection against sharp appreciation.","cat":"FX","diff":"MD","mod":"FX vol","concept":"Risk reversal"},{"q":"What is 'original sin' in EM sovereign debt?","o":["EM countries default more frequently than developed markets","EM countries historically cannot borrow internationally in their own currency \u2014 forced to take on foreign currency debt creating currency mismatch risk","EM central banks lack independence making monetary policy unreliable","EM countries have weaker property rights discouraging investment"],"a":1,"e":"'Original sin' describes the inability of EM countries to borrow internationally in their own currencies. They must borrow in USD/EUR, creating a dangerous mismatch: revenues in local currency, debt in foreign currency. Devaluation that helps competitiveness also inflates the real debt burden.","cat":"FX","diff":"MD","mod":"Currency crises","concept":"Original sin"},{"q":"What is currency board?","o":["A government committee setting exchange rate policy","A system where domestic currency is fully backed by foreign reserves at a fixed rate \u2014 removing domestic monetary policy discretion","A multilateral agreement fixing rates between regional trading partners","A central bank committee responsible only for FX intervention"],"a":1,"e":"A currency board fixes the exchange rate and backs every unit of domestic currency with equivalent foreign reserves. It eliminates monetary policy discretion \u2014 money supply only expands when reserves grow. Argentina's 1991-2001 convertibility and Hong Kong's dollar peg are examples.","cat":"FX","diff":"VP","mod":"Exchange rate regimes","concept":"Currency board"},{"q":"How does a strong US dollar typically affect EM economies?","o":["Benefits EM by reducing import costs","Creates headwinds: tightens global dollar liquidity, raises EM debt service costs, triggers capital outflows seeking USD yields","Strengthens EM by reducing their trade deficits","Minimal impact as most EM trade is invoiced in local currencies"],"a":1,"e":"Strong dollar tightens global financial conditions: raises cost of servicing USD-denominated EM debt, reduces dollar liquidity globally, triggers capital outflows from EM as investors return to USD assets, compresses commodity prices. The 2022 dollar surge inflicted severe damage across EM.","cat":"FX","diff":"VP","mod":"FX mechanics","concept":"Dollar and EM"},{"q":"What does an inverted yield curve typically signal?","o":["Strong economic growth ahead","Recession risk \u2014 markets expect future rate cuts as growth slows","Accelerating inflation requiring higher long-term yields","Central bank success in controlling inflation"],"a":1,"e":"Yield curve inversion (short rates above long rates) has preceded every US recession since 1955. It signals markets expect the central bank will need to cut rates sharply in the future \u2014 implying growth concerns outweigh inflation fears. The 2s10s spread is the most watched inversion signal.","cat":"RATES","diff":"ANALYST","mod":"Yield curve","concept":"Yield curve inversion"},{"q":"What is duration in fixed income?","o":["The time to maturity of a bond","A measure of a bond's price sensitivity to interest rate changes \u2014 the % price change for a 1% yield change","The average time to receive a bond's cash flows, weighted by present value","Both B and C \u2014 they are equivalent concepts"],"a":3,"e":"Duration has two equivalent definitions: (1) Macaulay duration \u2014 PV-weighted average time to receive cash flows, and (2) Modified duration \u2014 the bond's price sensitivity to yield changes. A bond with duration of 8 loses ~8% in price if yields rise 1%.","cat":"RATES","diff":"VP","mod":"Duration","concept":"Duration"},{"q":"Why do bond prices fall when interest rates rise?","o":["Higher rates reduce government creditworthiness","Existing bonds with lower fixed coupons become less attractive relative to new higher-yielding bonds \u2014 their price must fall to offer a competitive yield","Higher rates signal inflation eroding the real value of coupons","Rising rates increase the government's debt burden increasing default risk"],"a":1,"e":"Bond prices and yields move inversely. When market rates rise, newly issued bonds offer higher coupons. Existing bonds with lower fixed coupons become less attractive \u2014 their price must fall until their yield matches the new market rate.","cat":"RATES","diff":"ANALYST","mod":"Bond pricing","concept":"Price-yield relationship"},{"q":"What is a TIPS and how does it work?","o":["Treasury Inflation-Protected Security \u2014 principal adjusts with CPI, protecting purchasing power","A short-term US government bill with no coupon","A US Treasury bond with a floating rate linked to Fed Funds","A bond issued to finance specific infrastructure projects"],"a":0,"e":"TIPS have their principal adjusted by CPI. If inflation is 3%, a $1,000 TIPS becomes $1,030 in principal. The fixed coupon is applied to the adjusted principal. TIPS yields represent real yields \u2014 the difference between TIPS and nominal Treasury yields equals breakeven inflation.","cat":"RATES","diff":"VP","mod":"Real yields","concept":"TIPS mechanics"},{"q":"What is breakeven inflation?","o":["Inflation rate at which the Fed begins raising rates","Difference between nominal Treasury yields and TIPS yields \u2014 representing the market's implied inflation expectation","The point at which company revenues equal costs","The inflation rate needed to maintain real GDP growth"],"a":1,"e":"Breakeven inflation = Nominal Treasury yield minus TIPS yield. If the 10Y Treasury yields 4.5% and the 10Y TIPS yields 2.0%, breakeven inflation is 2.5% \u2014 the market's implied 10-year inflation expectation. Breakevens are a real-time measure of inflation expectations.","cat":"RATES","diff":"VP","mod":"Real yields","concept":"Breakeven inflation"},{"q":"What is quantitative tightening (QT)?","o":["Raising reserve requirements to reduce bank lending","Allowing bonds on the central bank's balance sheet to mature without reinvestment (or actively selling them), shrinking the balance sheet","Raising the rate on excess reserves to discourage bank lending","Imposing capital controls to prevent money leaving the banking system"],"a":1,"e":"QT is the reverse of QE \u2014 the central bank shrinks its balance sheet either by not reinvesting maturing bonds (passive QT) or actively selling bonds (active QT). It withdraws reserves and puts upward pressure on long-term yields by increasing bond supply. The Fed began QT in June 2022.","cat":"RATES","diff":"VP","mod":"QE/QT","concept":"Quantitative tightening"},{"q":"What is a credit default swap (CDS)?","o":["A bond issued by a corporation that defaults when dividends aren't paid","A derivative where the protection seller makes a payment to the buyer if a reference entity defaults \u2014 effectively insurance against credit events","A type of structured note referencing a basket of credit-risky assets","A government bond converting to equity in the event of sovereign default"],"a":1,"e":"A CDS is credit insurance: the protection buyer pays a regular premium (CDS spread in bps/year); the protection seller pays par minus recovery on default. CDS spreads reflect the market's assessment of default probability. Greek CDS widened to 10,000bp in 2012, implying near-certain default.","cat":"RATES","diff":"VP","mod":"Credit","concept":"Credit default swaps"},{"q":"What is the difference between investment grade and high yield bonds?","o":["Investment grade bonds have higher yields; high yield bonds have lower risk","Investment grade (rated BBB-/Baa3 or above) has lower default risk and lower yields; high yield (below BBB-) offers higher yields compensating for higher default risk","Investment grade refers only to government bonds; high yield to corporate bonds","Investment grade bonds are 10+ years; high yield bonds are short-term only"],"a":1,"e":"Investment grade: lower default risk, lower yields, wider investor base. High yield (junk): higher default risk, higher yields (typically 3-5%+ premium over IG), more volatile, more correlated with equities. HY spreads are a key real-time recession indicator \u2014 widening dramatically during economic stress.","cat":"RATES","diff":"ANALYST","mod":"Credit","concept":"IG vs HY"},{"q":"What is yield curve control (YCC)?","o":["A central bank targeting a specific yield on government bonds through unlimited purchases \u2014 capping long-term rates","A government policy of auctioning bonds at fixed yields","An IMF mechanism to stabilise sovereign bond yields during crises","A market convention for quoting bond yields in a standardised format"],"a":0,"e":"YCC: central bank commits to buy unlimited quantities of government bonds to maintain a target yield at a specific maturity. Japan's BOJ maintained a 0% target for 10Y JGBs from 2016. YCC caps long-term rates but can cause currency weakness when global rates rise and policy divergence becomes extreme.","cat":"RATES","diff":"VP","mod":"Monetary policy","concept":"Yield curve control"},{"q":"What is the credit spread and what drives it wider?","o":["Difference between a bond's coupon and its yield \u2014 driven wider by duration risk","Yield difference between a corporate bond and a comparable government bond \u2014 reflecting default and liquidity risk; widens during risk-off or credit stress","Difference between bid and ask prices in the bond market","Yield gap between investment grade and high yield bonds only"],"a":1,"e":"Credit spread is the extra yield demanded over the risk-free rate to compensate for default risk, liquidity risk, and uncertainty. Spreads widen during: recessions (higher default risk), financial stress (liquidity risk premium), and risk-off episodes. IG at 300bp and HY at 1000bp signals severe economic distress.","cat":"RATES","diff":"VP","mod":"Credit","concept":"Credit spreads"},{"q":"What is the repo market?","o":["A market for repurchasing used government securities at a discount","A short-term borrowing market where securities are sold with an agreement to repurchase \u2014 providing overnight liquidity to the financial system","A government bond issuance programme for retail investors","A market where central banks lend directly to corporations during stress"],"a":1,"e":"The repo (repurchase agreement) market provides trillions in daily short-term funding for banks, hedge funds, and dealers. It is the plumbing of the financial system. When repo markets seize (September 2019: overnight repo rates spiked to 10%), it signals systemic liquidity stress.","cat":"RATES","diff":"MD","mod":"Money markets","concept":"Repo market"},{"q":"What is the term premium in bond yields?","o":["Yield difference between corporate and government bonds","Extra compensation investors demand for holding long-term bonds rather than rolling short-term bonds \u2014 reflecting duration risk and inflation uncertainty","Difference between on-the-run and off-the-run Treasury yields","Yield pick-up from holding bonds in foreign currencies"],"a":1,"e":"The term premium is the extra yield investors require for uncertainty of holding long-duration bonds. It compensates for duration risk, inflation uncertainty, and liquidity risk over the bond's life. Term premia turned negative post-2008 as QE compressed long-end yields \u2014 contributing to flat and inverted yield curves in the 2010s.","cat":"RATES","diff":"MD","mod":"Yield curve","concept":"Term premium"},{"q":"What is convexity in fixed income?","o":["The tendency for bond prices to fall more than duration predicts when yields rise","The curvature in the price-yield relationship \u2014 bond prices rise more than duration predicts when yields fall, and fall less when yields rise","The relationship between a bond's coupon and its price sensitivity","How quickly a bond's duration changes over time"],"a":1,"e":"Convexity measures the curvature of the price-yield relationship. Positive convexity means bonds outperform pure duration predictions in both directions \u2014 gains are larger and losses smaller than duration predicts. Higher convexity is valuable. Zero-coupon bonds have the highest convexity; MBS often exhibit negative convexity.","cat":"RATES","diff":"MD","mod":"Duration","concept":"Convexity"},{"q":"What is the yield curve's relationship with the business cycle?","o":["Steep curves occur at cycle peaks; flat curves at troughs","Curves typically steepen during early recovery, flatten during expansion, and invert ahead of recession","Yield curves are coincident indicators with no predictive power","The yield curve only reflects monetary policy not the broader cycle"],"a":1,"e":"Yield curves are powerful cycle indicators. Early recovery: steep (central bank cuts, growth lifts long-end). Mid-cycle expansion: curve flattens as short rates rise with hikes. Late cycle: aggressive flattening or inversion as hikes compress future growth expectations. Inversion typically precedes recession by 12-24 months.","cat":"RATES","diff":"VP","mod":"Yield curve","concept":"Yield curve and business cycle"},{"q":"What is the OAS (Option-Adjusted Spread)?","o":["Spread of a bond over overnight rates, adjusted for settlement risk","A credit spread that strips out the value of embedded options \u2014 isolating the pure credit spread","Difference between a bond's yield and the swap rate","Average spread across all bonds in a credit index"],"a":1,"e":"OAS removes the value of embedded options (call features, prepayment options in MBS) from the bond's spread, leaving only credit spread and liquidity premium. For callable bonds, the yield spread includes compensation for the call option. OAS provides cleaner comparison across bonds with different option structures.","cat":"RATES","diff":"MD","mod":"Credit","concept":"Option-adjusted spread"},{"q":"What happened during the 1994 Bond Massacre?","o":["The Fed's surprise 300bp hike caused the worst bond losses in decades","The Fed began an unexpected hiking cycle from 3% to 6%, triggering a global bond selloff \u2014 bankrupting Orange County and contributing to the Mexican peso crisis","A rogue trader caused massive bond losses through unauthorised positions","US government default fears triggered a bond selloff across developed markets"],"a":1,"e":"The Fed hiked from 3% to 6% in 1994 \u2014 surprising markets after years of low rates. Global bond yields surged, causing severe losses. Orange County filed for bankruptcy after leveraged bond bets soured. Mexican peso came under pressure as capital fled EM. The episode is a template for how rapid rate cycles cause unexpected casualties.","cat":"RATES","diff":"VP","mod":"Historical","concept":"1994 bond massacre"},{"q":"What is the Equity Risk Premium (ERP)?","o":["Excess return of growth stocks over value stocks","Expected excess return of equities over the risk-free rate \u2014 compensation for additional equity risk","Premium paid for index options relative to single-stock options","Return difference between developed and emerging market equities"],"a":1,"e":"The ERP is the extra return investors expect for holding equities versus risk-free assets. Historically ~5-6% per year for US equities. The ERP contracts during bull markets and expands during crises when equities are cheap relative to bonds.","cat":"EQUITY","diff":"VP","mod":"Equity valuation","concept":"Equity risk premium"},{"q":"How do rising real interest rates affect equity valuations?","o":["Rising real rates boost equities by signaling stronger growth","Rising real rates compress P/E multiples \u2014 the discount rate applied to future earnings increases, reducing the present value of growth stocks","Rising real rates have no direct effect on equities; only nominal rates matter","Rising real rates benefit equities by reducing inflation and lowering input costs"],"a":1,"e":"Rising real rates increase the discount rate applied to future earnings, reducing their present value. This is particularly damaging for high-multiple growth stocks. In 2022, the surge in real yields from -1% to +2% drove NASDAQ -33% \u2014 a direct mathematical consequence of higher discount rates.","cat":"EQUITY","diff":"VP","mod":"Equity valuation","concept":"Rates and equity valuation"},{"q":"What is the CAPE ratio?","o":["Current P/E adjusted for the business cycle","Price divided by 10-year average inflation-adjusted earnings \u2014 smoothing cyclical fluctuations to assess long-term valuation","P/E ratio of cyclical stocks relative to defensive stocks","Ratio of equity market capitalisation to GDP"],"a":1,"e":"CAPE (Shiller P/E): stock price divided by 10-year average real earnings. By smoothing over a full cycle, it avoids distortion from cyclically depressed or elevated profits. Above 30x historically signals expensive valuations. US CAPE above 30x has been cited as a warning since the late 1990s.","cat":"EQUITY","diff":"VP","mod":"Equity valuation","concept":"CAPE ratio"},{"q":"What is the VIX and what does it measure?","o":["CBOE Volatility Index \u2014 measures realised volatility of S&P 500 over the past 30 days","CBOE Volatility Index \u2014 measures implied volatility of S&P 500 options over the next 30 days","Measure of the bid-ask spread in S&P 500 options \u2014 a proxy for market liquidity","Rate of change of the S&P 500 \u2014 a momentum indicator"],"a":1,"e":"The VIX measures implied volatility derived from S&P 500 options prices over the next 30 days. It reflects the market's expectation of future volatility \u2014 not a directional view. VIX above 30 signals elevated fear; below 15 signals complacency. It spikes during crises: 82 in March 2020, 80 in October 2008.","cat":"EQUITY","diff":"ANALYST","mod":"Volatility","concept":"VIX"},{"q":"What is the relationship between VIX and equity market direction?","o":["VIX and equities move together \u2014 high VIX accompanies rising markets","VIX and equities are typically negatively correlated \u2014 VIX rises when equities fall, reflecting increased uncertainty during selloffs","VIX leads equity markets by approximately 30 days","VIX and equities are uncorrelated \u2014 VIX reflects future volatility regardless of direction"],"a":1,"e":"VIX and equities are negatively correlated (typically -0.7 to -0.8). When equities sell off, demand for put options increases, pushing up implied vol. When markets rise calmly, vol demand falls. This 'fear gauge' relationship makes VIX useful for hedging \u2014 long VIX is a natural equity hedge.","cat":"EQUITY","diff":"VP","mod":"Volatility","concept":"VIX-equity correlation"},{"q":"What caused 'Volmageddon' in February 2018?","o":["A flash crash caused by algorithmic trading errors","Inverse VIX ETPs were forced to buy VIX futures as volatility spiked, amplifying the initial selloff in a self-reinforcing loop","Federal Reserve rate hike larger than expected triggered simultaneous selling","A geopolitical shock caused sudden repricing of equity risk globally"],"a":1,"e":"In February 2018, a modest equity selloff triggered a VIX spike. Inverse VIX ETPs (like XIV) had sold volatility \u2014 when VIX rose, they were forced to buy VIX futures to rebalance, pushing VIX higher, forcing more buying. XIV lost 96% in a day. The episode highlighted systemic risks from crowded short-vol positioning.","cat":"EQUITY","diff":"MD","mod":"Volatility","concept":"Volmageddon 2018"},{"q":"What is sector rotation and how does it relate to the economic cycle?","o":["Shifting between sectors has no systematic relationship with the economic cycle","Different sectors outperform at different cycle stages: defensives in recession, cyclicals in early recovery, financials in mid-cycle, and defensives again late cycle","Sector rotation is driven purely by valuation, not economic cycle","Technology always outperforms; other sectors rotate around it"],"a":1,"e":"Sector rotation follows the economic cycle: Recession \u2192 defensives (utilities, healthcare, staples). Early recovery \u2192 cyclicals (materials, industrials), consumer discretionary. Mid-cycle \u2192 technology, financials. Late cycle \u2192 energy, materials. The 2022 rotation from growth to value/energy was a textbook late-cycle/stagflation rotation.","cat":"EQUITY","diff":"VP","mod":"Sector rotation","concept":"Sector rotation"},{"q":"What is the difference between realised and implied volatility?","o":["Realised vol is calculated from options prices; implied vol from historical returns","Implied vol is forward-looking expectation derived from options prices; realised vol is calculated from actual historical price movements","They measure the same thing but over different horizons","Realised vol applies to indices; implied vol to individual stocks"],"a":1,"e":"Implied vol (IV): extracted from options \u2014 the market's expectation of future volatility. Realised vol (RV): calculated from actual historical price movements. The 'volatility risk premium' is the persistent tendency for IV to exceed RV \u2014 options are systematically overpriced, which is why short-volatility strategies have historically been profitable (with crash risk).","cat":"EQUITY","diff":"MD","mod":"Volatility","concept":"Implied vs realised volatility"},{"q":"What caused the dot-com bubble to inflate and burst?","o":["Federal Reserve rate cuts created excess liquidity flowing into technology stocks","Speculative enthusiasm for internet companies with no profits, funded by cheap VC and retail FOMO, inflated valuations to extreme levels; the bubble burst when profitability failed to materialise and the Fed raised rates","A specific corporate accounting scandal triggered loss of confidence across tech","Regulatory changes requiring internet companies to pay taxes collapsed their valuations"],"a":1,"e":"The late 1990s dot-com bubble: internet euphoria drove extreme valuations for money-losing companies. Cheap VC funding, IPO mania, and retail FOMO created a self-reinforcing bubble. NASDAQ peaked at 5,048 in March 2000. As profitability failed to materialise and the Fed raised rates 175bp, the bubble collapsed \u2014 NASDAQ fell 78% by 2002.","cat":"EQUITY","diff":"ANALYST","mod":"Historical crises","concept":"Dot-com bubble"},{"q":"What is the put-call ratio and what does an extreme reading signal?","o":["Ratio of a company's equity to debt","Ratio of put option volume to call option volume \u2014 extreme readings signal contrarian opportunities: very high put/call ratios suggest excessive bearishness (potential buy signal)","Ratio of equity market cap to bond market cap","Ratio of S&P 500 implied vol to realised vol"],"a":1,"e":"The put-call ratio measures bearish vs bullish sentiment via options flow. High put/call (heavy put buying) signals fear and bearish positioning \u2014 historically a contrarian buy signal when extreme. Low put/call signals complacency \u2014 a potential warning. Used alongside VIX and survey data for sentiment analysis.","cat":"EQUITY","diff":"VP","mod":"Equity sentiment","concept":"Put-call ratio"},{"q":"Why is oil priced in US dollars globally?","o":["The US is the world's largest oil producer and sets prices","The 1970s Petrodollar system tied OPEC oil sales to USD \u2014 creating structural global dollar demand","IMF regulations require commodity pricing in the reserve currency","The USD is the most stable currency preferred by oil exporters"],"a":1,"e":"The Petrodollar system emerged after Nixon ended dollar-gold convertibility in 1971. Saudi Arabia agreed to price oil in USD and invest surpluses in US Treasuries in exchange for US security guarantees. This created structural global dollar demand \u2014 every country needed USD to buy oil, reinforcing dollar hegemony.","cat":"COMMODITIES","diff":"VP","mod":"Oil","concept":"Petrodollar system"},{"q":"What is OPEC+ and how does it influence oil prices?","o":["A free trade agreement between oil-producing nations","An expanded OPEC cartel including Russia and other non-OPEC producers \u2014 coordinating production cuts/increases to manage oil prices","A financial derivatives exchange for oil futures","A UN body regulating international oil trade"],"a":1,"e":"OPEC+ includes OPEC members plus Russia and other non-OPEC producers. By coordinating production quotas, it controls a significant share of global supply. Production cuts tighten supply and support prices; increases ease prices. US shale growth reduced OPEC+'s pricing power significantly in the 2010s.","cat":"COMMODITIES","diff":"ANALYST","mod":"Oil","concept":"OPEC+ mechanics"},{"q":"What caused WTI oil prices to go negative in April 2020?","o":["A cyberattack on oil trading systems caused pricing errors","COVID-19 destroyed demand while storage was full \u2014 holders of May futures faced physical delivery but could find nowhere to store oil, forcing them to pay others to take delivery","Saudi Arabia and Russia flooded the market simultaneously","US regulations required oil companies to accept negative prices"],"a":1,"e":"In April 2020, WTI fell to -$37/barrel. COVID destroyed ~30% of global demand. Storage was near capacity. May futures holders faced physical delivery. Unable to store or sell, they paid counterparties to take oil. It was a logistics crisis \u2014 the physical storage constraint \u2014 not purely financial.","cat":"COMMODITIES","diff":"VP","mod":"Oil","concept":"Negative oil prices 2020"},{"q":"Why is copper known as 'Dr Copper'?","o":["Copper prices predict inflation with a 3-month lead time","Copper's wide use in construction, manufacturing and electronics makes its price a reliable leading indicator of global economic activity","Copper was historically used to back currencies","Copper mining employment is the most accurate predictor of industrial production"],"a":1,"e":"Copper's use across construction (wiring, plumbing), manufacturing, and electronics makes its price a sensitive barometer of global economic activity. When China and global growth accelerate, copper demand rises. When growth slows, copper falls. Copper peaked with China's infrastructure boom (2011) and fell ahead of the 2015-16 China slowdown.","cat":"COMMODITIES","diff":"ANALYST","mod":"Metals","concept":"Dr Copper"},{"q":"What drives gold prices in the short to medium term?","o":["Gold tracks inflation \u2014 as inflation rises, gold always rises","US real yields and the USD are the primary drivers \u2014 gold rises when real yields fall and/or USD weakens","Gold tracks global jewellery demand mainly from India and China","Gold prices are primarily driven by central bank reserve diversification"],"a":1,"e":"Gold is primarily driven by US real yields (inverse relationship) and USD (inverse). When real yields fall (as in 2020), holding gold has a lower opportunity cost vs yield-bearing assets. When real yields surge (as in 2022), gold becomes less attractive. USD strength also reduces gold's purchasing power in non-USD currencies.","cat":"COMMODITIES","diff":"VP","mod":"Gold","concept":"Gold price drivers"},{"q":"What is backwardation in commodity futures markets?","o":["Near-term futures prices are higher than longer-dated futures \u2014 typically signaling tight spot supply","Longer-dated futures prices are higher than near-term \u2014 typical for commodities with high storage costs","Commodity prices fall below production costs forcing supply cuts","Commodity futures and spot prices diverge due to currency effects"],"a":0,"e":"Backwardation: near-term futures prices above longer-dated prices. Signals tight immediate supply or high convenience yield. Oil markets enter backwardation when OPEC cuts tighten near-term supply. Contango (the opposite) occurs when supply is ample and storage costs dominate.","cat":"COMMODITIES","diff":"MD","mod":"Futures mechanics","concept":"Backwardation vs contango"},{"q":"What is the 'resource curse'?","o":["Environmental damage caused by commodity extraction","The paradox where countries with abundant natural resources often experience slower economic growth, weaker institutions, and more conflict \u2014 plus Dutch Disease destroying manufacturing competitiveness","Economic damage to manufacturing when commodity booms cause currency appreciation","Both B and C \u2014 the resource curse encompasses multiple negative effects"],"a":3,"e":"The resource curse has two main dimensions: (1) Dutch Disease \u2014 commodity booms cause currency appreciation, destroying manufacturing; (2) Institutional curse \u2014 commodity wealth concentrated in government hands leads to corruption, poor governance, and conflict. Norway's sovereign wealth fund is often cited as the successful exception.","cat":"COMMODITIES","diff":"MD","mod":"Macro","concept":"Resource curse"},{"q":"What are commodity-exporting currencies and which factors drive them?","o":["All currencies from countries in the Southern Hemisphere","Currencies of countries whose exports are dominated by commodities \u2014 AUD, CAD, NOK, ZAR track commodity prices because rising commodity prices boost export revenues and attract capital","Currencies pegged to commodity prices through formal exchange rate arrangements","EM currencies in general \u2014 all EM are commodity-dependent"],"a":1,"e":"For commodity exporters (AUD, CAD, NOK, ZAR, CLP), commodity prices directly affect terms of trade, fiscal revenues, and GDP growth. Rising iron ore and copper prices boost Australian export earnings and attract foreign investment into AUD assets, appreciating AUD. This is why AUD/USD closely tracks iron ore and Chinese growth expectations.","cat":"COMMODITIES","diff":"VP","mod":"Commodity currencies","concept":"Commodity currencies"},{"q":"What caused Black Monday on 19 October 1987?","o":["The Fed raised rates aggressively to fight inflation","Portfolio insurance strategies mechanically sold S&P 500 futures as markets fell, creating a self-reinforcing spiral that caused a 22% single-day crash","A major US bank failure triggered systemic crisis","Trade war tariffs imposed by the US government caused immediate recession fear"],"a":1,"e":"Black Monday (Oct 19, 1987): S&P 500 fell 22.6% in a single day. Portfolio insurance \u2014 a hedging strategy using dynamic futures selling \u2014 became self-reinforcing. As markets fell, the strategy sold more futures, pushing prices lower, triggering more selling. An early demonstration of how systematic strategies amplify volatility.","cat":"EQUITY","diff":"VP","mod":"Historical crises","concept":"Black Monday 1987"},{"q":"What was Long-Term Capital Management (LTCM) and why did it fail?","o":["A technology hedge fund that failed due to Y2K computer errors","A fixed income arbitrage fund run by Nobel Prize winners that used extreme leverage; the 1998 Russia default caused spread widening that wiped out its equity","A Japanese bank that failed due to non-performing property loans","A US savings institution that failed due to aggressive property lending"],"a":1,"e":"LTCM was a highly leveraged fixed income arbitrage fund \u2014 $125bn in assets on $4.7bn equity (26:1 leverage). Its models assumed spreads would converge. Russia's 1998 default triggered flight to quality \u2014 spreads widened dramatically. LTCM's equity was wiped out. The Fed orchestrated a $3.6bn private sector rescue to prevent systemic contagion.","cat":"RATES","diff":"VP","mod":"Historical crises","concept":"LTCM 1998"},{"q":"What was a CDO and its role in the 2008 crisis?","o":["A US government bond with variable rates that reset based on housing prices","A structured product pooling mortgages into tranches rated from AAA to equity; ratings agency failures allowed toxic mortgage risk to be mislabelled as safe and spread globally","A derivative requiring banks to purchase mortgages at fixed prices","A regulatory tool used by the Fed to manage bank capital"],"a":1,"e":"CDOs pooled mortgage-backed securities into tranches. Rating agencies assigned AAA ratings to senior tranches despite underlying subprime exposure, based on flawed correlation assumptions. This allowed toxic mortgage risk to be sold globally as 'safe' assets. When housing prices fell and correlations spiked to 1, CDOs collapsed, spreading losses globally.","cat":"MACRO","diff":"VP","mod":"Historical crises","concept":"CDOs and 2008 GFC"},{"q":"What was the significance of Lehman Brothers' bankruptcy in September 2008?","o":["It was the largest bankruptcy in US history but had limited market impact","Lehman's failure froze global money markets \u2014 Reserve Primary Fund 'broke the buck', commercial paper markets seized, and interbank lending collapsed, transforming a credit crisis into a systemic financial crisis","The Treasury's decision to save Lehman prevented a worse crisis","Lehman's bankruptcy was primarily a UK financial event"],"a":1,"e":"Lehman's bankruptcy on September 15 2008 was the turning point. Reserve Primary Fund 'broke the buck', triggering mass money market redemptions. Commercial paper markets seized. Interbank lending froze. TED spreads (interbank vs Treasury) spiked to 460bp. What had been a credit crisis became a systemic panic.","cat":"MACRO","diff":"VP","mod":"Historical crises","concept":"Lehman Brothers 2008"},{"q":"What triggered the 2010-12 Eurozone sovereign debt crisis?","o":["The ECB raised rates too aggressively in 2010","Greece revealed its fiscal deficit was far larger than reported (13% of GDP vs 6%), triggering a loss of market confidence that spread to Ireland, Portugal, Spain and Italy","A collapse in European bank lending caused simultaneous recession","German constitutional court challenges to ECB bond purchases froze sovereign bond markets"],"a":1,"e":"In late 2009, Greece's new government revealed the true deficit was 13.6% of GDP (vs the 6% previously reported). Markets lost confidence in Greek fiscal management, spreads surged, and contagion spread to Ireland, Portugal, and then larger economies Spain and Italy. The fear was eurozone breakup.","cat":"MACRO","diff":"VP","mod":"Historical crises","concept":"Eurozone crisis trigger"},{"q":"What did Mario Draghi mean by 'whatever it takes' in July 2012?","o":["The ECB would print unlimited money to fund Eurozone government deficits","The ECB would purchase unlimited quantities of sovereign bonds if necessary to preserve the euro \u2014 signaling the end of the existential threat to the eurozone","EU member states would accept unlimited fiscal transfers","The ECB would cut rates to whatever level was needed"],"a":1,"e":"In July 2012 with Italian and Spanish yields above 7%, Draghi said the ECB would do 'whatever it takes to preserve the euro. And believe me, it will be enough.' The ECB then announced OMT \u2014 unlimited bond purchases. Spreads collapsed immediately. The programme never had to be activated \u2014 the announcement alone was sufficient.","cat":"MACRO","diff":"ANALYST","mod":"Historical crises","concept":"Draghi whatever it takes"},{"q":"What is the bank-sovereign doom loop?","o":["Self-reinforcing cycle where bank failures cause government spending to rise","Weak sovereigns cannot support their banks (whose assets include sovereign bonds losing value); bank stress weakens sovereigns further, creating a self-reinforcing downward spiral","Relationship between central bank printing and bank profitability","Mechanism by which recession causes both bank failures and fiscal crises"],"a":1,"e":"The bank-sovereign doom loop: weak banks hold large quantities of their own government's bonds. When sovereign yields rise (bonds fall), bank balance sheets weaken. Weak banks need government support, increasing the fiscal deficit. Higher deficits push yields higher, causing more bank losses. Most acute in Ireland, Spain and Italy in 2011-12.","cat":"MACRO","diff":"MD","mod":"Historical crises","concept":"Bank-sovereign doom loop"},{"q":"What was unique about the 2020 COVID economic shock?","o":["COVID was the first recession caused by a financial crisis","COVID was a simultaneous supply and demand shock \u2014 supply chains disrupted and demand collapsed simultaneously across a uniquely short timeframe; unlike financial crises, the cause was external and non-financial","COVID was purely a demand shock caused by consumer confidence collapse","COVID uniquely affected only the services sector"],"a":1,"e":"COVID was extraordinary: an external, non-financial shock that simultaneously destroyed supply (lockdowns, supply chains) and demand (fear, job losses, restrictions). GDP fell 30%+ annualised in Q2 2020. But unlike financial crises (which damage credit intermediation), the financial system remained intact, enabling a faster recovery.","cat":"MACRO","diff":"VP","mod":"Historical crises","concept":"COVID economic shock"},{"q":"What was the 'transitory' inflation debate of 2021?","o":["Whether the 2021 inflation spike was permanent or temporary \u2014 the Fed judged it transitory and delayed tightening, which proved wrong","A Fed debate about whether to target 2% or 3% inflation","A Treasury debate about whether fiscal stimulus would cause hyperinflation","A market debate about whether QE would eventually cause inflation"],"a":0,"e":"In 2021, as CPI rose, the Fed and Treasury argued inflation was 'transitory' \u2014 a temporary supply-side disruption that would self-correct. The assessment proved wrong as inflation became broad-based and persistent. The delay in tightening forced the most aggressive hiking cycle in 40 years in 2022.","cat":"MACRO","diff":"VP","mod":"Historical crises","concept":"Transitory inflation debate"},{"q":"What is moral hazard in the context of bank bailouts?","o":["The risk that bank employees engage in fraud when not monitored","The perception that 'too big to fail' banks will be rescued by government, encouraging excessive risk-taking because losses will be socialised while profits remain private","The legal liability of government officials who approve bank rescues","The risk that bank rescues set a precedent encouraging more failures"],"a":1,"e":"Moral hazard: if banks believe they will be rescued when in distress, they have incentive to take excessive risks. 'Too big to fail' is the ultimate moral hazard \u2014 systemically important banks know a disorderly failure would be catastrophic, making government rescue nearly certain. Post-2008 regulations (Dodd-Frank, Basel III) aimed to address this.","cat":"MACRO","diff":"VP","mod":"Historical crises","concept":"Moral hazard"},{"q":"What is central bank independence and why does it matter?","o":["Central banks setting their own salaries without government approval","Insulation of monetary policy from short-term political pressure \u2014 allowing credible commitment to price stability even when it requires unpopular rate hikes","Central banks operating without any regulatory oversight","Ability of central banks to set their own inflation targets"],"a":1,"e":"Central bank independence allows policymakers to make unpopular decisions without political interference. Research consistently shows independent central banks achieve lower inflation. When independence is compromised (Turkey, Argentina), markets lose confidence in the currency and inflation rises.","cat":"MACRO","diff":"VP","mod":"Central banks","concept":"Central bank independence"},{"q":"What is the Fed's dual mandate?","o":["Price stability (2% inflation) and financial system stability","Maximum employment and stable prices (2% inflation)","Maximum employment, stable prices, and moderate long-term interest rates","Price stability, maximum employment, and balanced international trade"],"a":2,"e":"The Fed's statutory mandate from Congress is maximum employment, stable prices, AND moderate long-term interest rates. In practice, the Fed focuses on the first two as its 'dual mandate'. Most other central banks have a single mandate of price stability.","cat":"MACRO","diff":"ANALYST","mod":"Central banks","concept":"Fed dual mandate"},{"q":"What is the Taylor Rule?","o":["A guideline for central banks to raise rates by exactly 25bp per meeting","A formula suggesting appropriate nominal rates based on the output gap and inflation deviation from target","A rule requiring central banks to target nominal GDP growth","A guideline that central banks should never cut rates below the previous cycle's trough"],"a":1,"e":"Taylor Rule (John Taylor, 1993): Nominal rate = r* + inflation + 0.5\u00d7(inflation gap) + 0.5\u00d7(output gap). Provides a systematic benchmark for appropriate monetary policy. When rates are well below Taylor Rule prescriptions (as in 2021-22), policy is considered very accommodative.","cat":"MACRO","diff":"MD","mod":"Central banks","concept":"Taylor Rule"},{"q":"What is the Volcker disinflation?","o":["Paul Volcker's decision to allow the dollar to depreciate in 1985","Fed Chair Volcker's deliberate induction of two recessions by raising rates to 20% to break 14% inflation \u2014 demonstrating credible central bank commitment can defeat entrenched inflation at high short-term cost","Volcker's 1970 decision to end gold convertibility creating fiat money","The 1987 stock market crash during Volcker's tenure"],"a":1,"e":"Volcker's 1979-82 tightening: rates to 20%, two recessions, unemployment to 10.8%. But inflation was broken \u2014 from 14% to 3% by 1983. The 'Volcker moment' demonstrates what it takes to defeat entrenched inflation: credible, sustained tightening despite severe short-term pain. Powell's 2022-23 hiking cycle was frequently compared to Volcker.","cat":"MACRO","diff":"VP","mod":"Central banks","concept":"Volcker disinflation"},{"q":"What is 'average inflation targeting' (AIT)?","o":["A policy targeting average inflation across all G7 countries","A framework where the Fed allows inflation to run above 2% temporarily after periods below 2% to achieve an average of 2% over time","A policy targeting the average of CPI and PCE inflation","A rolling 10-year average inflation target"],"a":1,"e":"AIT (August 2020): the Fed shifted from targeting 2% inflation at each point in time to achieving 2% on average over time. After years of below-2% inflation, AIT justified keeping rates near zero even as inflation began rising in 2021. Critics argue AIT delayed tightening, contributing to the 2022 inflation surge.","cat":"MACRO","diff":"VP","mod":"Central banks","concept":"Average inflation targeting"},{"q":"What is Jackson Hole and why does it matter?","o":["An annual Federal Reserve board meeting setting monetary policy for the following year","Annual conference hosted by the Kansas City Fed where central bank chiefs signal future policy shifts \u2014 historically the venue for major policy announcements","A regulatory conference where Basel capital requirements are negotiated","A G20 finance ministers meeting setting fiscal policy coordination"],"a":1,"e":"Jackson Hole (Wyoming): annual Kansas City Fed symposium attended by global central bank governors. The Fed chair typically uses it to signal policy direction. Key moments: Bernanke signalled QE2 in 2010, Draghi hinted at ECB QE in 2014, Powell's 2022 speech delivered the bluntest hawkish pivot in decades in just 8 minutes.","cat":"MACRO","diff":"VP","mod":"Central banks","concept":"Jackson Hole"},{"q":"What is helicopter money?","o":["Central bank purchases of equity ETFs to stimulate the stock market","Direct monetary transfers from the central bank to households \u2014 bypassing the banking system to directly boost spending power","Central bank aerial surveillance of economic activity","QE where the central bank purchases very short-term government bills"],"a":1,"e":"Helicopter money (Milton Friedman's analogy): the central bank creates money and transfers it directly to households, bypassing banks. In theory, it cannot fail to stimulate spending. COVID stimulus cheques combined with money printing were quasi-helicopter money, though technically fiscal policy funded by central bank asset purchases.","cat":"MACRO","diff":"VP","mod":"Central banks","concept":"Helicopter money"},{"q":"What is the Bank for International Settlements (BIS)?","o":["The international lender of last resort providing emergency loans to governments","The 'central bank for central banks' \u2014 facilitating cooperation, providing banking services to central banks, and conducting influential macro research","A global financial regulator setting rules for banks across all jurisdictions","The IMF's executive arm implementing financial sector reforms"],"a":1,"e":"BIS ('central bank for central banks'): provides banking services to central banks (holding FX reserves), facilitates coordination (Basel Committee), and produces highly influential macro-financial research. BIS quarterly reviews are closely followed for early warning signals on global financial stability. The Basel capital accords emerged from BIS-hosted committees.","cat":"MACRO","diff":"VP","mod":"Central banks","concept":"BIS"},{"q":"What is the lender of last resort function?","o":["The IMF's role in providing emergency sovereign loans","The central bank's willingness to provide emergency liquidity to solvent but illiquid banks during panics \u2014 preventing bank runs from becoming systemic crises (Bagehot: lend freely at penalty rates against good collateral)","The US Treasury's backstop of money market funds during crises","A commercial bank's commitment to provide credit lines to corporate clients during stress"],"a":1,"e":"Lender of last resort (Walter Bagehot, 1873): central banks should lend freely to solvent banks during panics, at penalty rates (to prevent moral hazard), against good collateral. The distinction between illiquid (needs LoLR) and insolvent (needs government capital) is crucial \u2014 central banks should not rescue insolvent banks.","cat":"MACRO","diff":"VP","mod":"Central banks","concept":"Lender of last resort"},{"q":"What is the BOJ's yield curve control (YCC)?","o":["A policy capping short-term rates at -0.1% to prevent deflation","A policy targeting the 10Y JGB yield at approximately 0% through unlimited bond purchases \u2014 effectively controlling the yield curve across maturities","A policy allowing JGB yields to float freely while intervening only in currency markets","A policy buying both JGBs and equities (via ETFs) to stimulate the economy"],"a":1,"e":"BOJ's YCC (2016): target 10Y JGB yield at 0% (later widened to \u00b10.5% in Dec 2022, then \u00b11.0% in 2023). The BOJ commits to buying unlimited JGBs to defend this target. YCC kept JPY weak as global rates rose in 2022, as the BOJ-Fed divergence became extreme.","cat":"RATES","diff":"VP","mod":"Central banks","concept":"BOJ yield curve control"},{"q":"What is the 60/40 portfolio and why did it struggle in 2022?","o":["60% bonds and 40% equities \u2014 suffered because bond prices fell due to low yields","60% equities and 40% bonds \u2014 historically diversified because equity/bond correlation is negative; in 2022 both fell simultaneously as rate hikes damaged equities AND bonds, removing the hedge","60% developed markets and 40% emerging markets equities","A leveraged portfolio structure caught on the wrong side of the yield curve"],"a":1,"e":"The 60/40 portfolio relies on negative stock-bond correlation for diversification \u2014 bonds rising when stocks fall. In 2022, this correlation turned sharply positive: rate hikes crushed bond prices (worst year in a century) AND equity valuations simultaneously. The 60/40 had its worst year since 1937.","cat":"MACRO","diff":"VP","mod":"Cross-asset","concept":"60/40 portfolio"},{"q":"In a classic 'risk-off' environment, which assets typically benefit?","o":["High-yield bonds, emerging market equities, and commodity currencies","US Treasuries, USD, JPY, CHF, and gold \u2014 safe-haven assets","Cyclical equities, oil, and high-beta emerging market currencies","Technology stocks and long-duration assets due to flight-to-quality buying"],"a":1,"e":"Risk-off triggers flight to safety: US Treasuries (safest store of value), USD (global reserve currency), JPY and CHF (low-yielding safe havens with large net creditor positions), and gold (inflation-independent store of value). Risk assets \u2014 HY bonds, EM, equities, commodity currencies \u2014 sell off simultaneously.","cat":"MACRO","diff":"ANALYST","mod":"Cross-asset","concept":"Risk-off dynamics"},{"q":"What is the 'Minsky moment'?","o":["The moment a central bank loses credibility due to excessive money printing","The point when speculative debt builds to a level where asset sales to repay loans cause a self-reinforcing collapse \u2014 named after Hyman Minsky's financial instability hypothesis","The inflection point in business cycles where growth transitions from expansion to recession","The moment when market volatility shifts from low to high regime"],"a":1,"e":"Hyman Minsky: in good times, borrowers shift from 'hedge' financing (cash flows cover debt) to 'speculative' (interest only) to 'Ponzi' (need asset sales or new borrowing). A 'Minsky moment' is when Ponzi finance collapses \u2014 asset sales to repay debt drive prices down, triggering more forced selling. The 2008 mortgage crisis was a textbook Minsky moment.","cat":"MACRO","diff":"MD","mod":"Cross-asset","concept":"Minsky moment"},{"q":"What is the TED spread and what does it signal?","o":["Difference between 10Y and 2Y Treasury yields \u2014 a yield curve slope indicator","Spread between 3-month LIBOR (interbank lending rate) and 3-month Treasury bill yield \u2014 measuring bank credit risk and interbank market stress","Difference between US and European government bond yields","Spread between investment grade and high yield corporate bond yields"],"a":1,"e":"TED spread (Treasury-EuroDollar): 3M LIBOR minus 3M T-bill yield. Normal: 10-50bp. Crisis: spiked to 460bp in October 2008 post-Lehman, signaling complete breakdown of interbank trust. A rising TED spread is an early warning of financial stress and bank counterparty risk.","cat":"MACRO","diff":"MD","mod":"Cross-asset","concept":"TED spread"},{"q":"What is a macro regime and why does identifying it matter?","o":["The political government in power determining fiscal policy direction","The combination of growth and inflation environment that determines which asset classes outperform \u2014 e.g. goldilocks (rising growth, falling inflation) favours equities; stagflation favours commodities","The central bank's policy framework (inflation targeting, price level targeting, etc.)","The regulatory environment governing financial markets in a given period"],"a":1,"e":"Macro regimes combine growth and inflation dynamics: Growth\u2191/Inflation\u2193 (goldilocks \u2192 equities, credit), Growth\u2191/Inflation\u2191 (reflation \u2192 commodities), Growth\u2193/Inflation\u2191 (stagflation \u2192 commodities, cash), Growth\u2193/Inflation\u2193 (deflation \u2192 bonds, gold). Identifying the regime and transition points is central to macro investing.","cat":"MACRO","diff":"VP","mod":"Cross-asset","concept":"Macro regimes"},{"q":"What is the wealth effect?","o":["Tendency for wealthy people to consume a higher proportion of their income","Mechanism by which rising asset prices (equities, housing) increase household wealth, boosting consumption \u2014 and conversely, falling asset prices reduce consumption","Effect of wealth redistribution policies on economic growth","Tendency for wealthy households to underreport income in economic surveys"],"a":1,"e":"The wealth effect: as asset prices rise, households feel wealthier and increase consumption. For every $1 of stock market gains, US consumption rises approximately 3-5 cents. This is why central banks care about equity market levels \u2014 QE-driven asset price appreciation was deliberately intended to stimulate growth through this channel.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"Wealth effect"},{"q":"What is the leverage cycle?","o":["Regular pattern of corporate debt issuance following the business cycle","Self-reinforcing mechanism where rising asset prices allow more borrowing (higher collateral values), which drives more buying, which raises prices further \u2014 until the cycle reverses and falling prices force deleveraging","Regulatory cycle governing bank leverage ratios","Tendency for leveraged buyout activity to peak near market tops"],"a":1,"e":"The leverage cycle (Geanakoplos): asset price rises increase collateral values, allowing more borrowing, which funds more purchases, further raising prices. In reverse: falling prices reduce collateral, trigger margin calls, forced selling depresses prices further. This amplification mechanism explains why financial crises are so violent.","cat":"MACRO","diff":"MD","mod":"Cross-asset","concept":"Leverage cycle"},{"q":"What is the global financial cycle?","o":["The synchronized business cycles of G7 economies due to trade integration","The observation that a single global factor (predominantly US monetary policy and the VIX) drives credit conditions, risk appetite, and asset prices across the world \u2014 implying global financial conditions constrain national monetary sovereignty","The regular pattern of global recessions occurring approximately every 10 years","The cycle of financial deregulation and re-regulation following crises"],"a":1,"e":"The global financial cycle (H\u00e9l\u00e8ne Rey, 2013): a single global factor \u2014 primarily US monetary policy and the VIX \u2014 explains a significant fraction of credit growth, capital flows, and asset prices globally. This challenges the Mundell-Fleming trilemma: even with floating exchange rates, countries cannot fully escape the global financial cycle.","cat":"MACRO","diff":"MD","mod":"Cross-asset","concept":"Global financial cycle"},{"q":"What is contagion in financial markets?","o":["The spread of a central bank's monetary policy stance to other central banks","Transmission of financial stress from one asset, market, or country to others \u2014 often through correlated selling, funding chain linkages, or confidence spillovers that exceed what fundamentals would justify","Gradual adoption of financial regulations across multiple jurisdictions","Mechanism by which trade linkages transmit economic recessions across borders"],"a":1,"e":"Financial contagion occurs when stress spreads beyond what fundamental linkages explain. Mechanisms: (1) portfolio channel \u2014 investors sell other positions to meet margin calls; (2) funding channel \u2014 interbank funding freezes; (3) confidence \u2014 pure panic. The 1997 Asian crisis and 2008 GFC both showed rapid, widespread contagion.","cat":"MACRO","diff":"VP","mod":"Cross-asset","concept":"Financial contagion"},{"q":"What is credit impulse and why is it a leading indicator?","o":["Change in credit spreads over a quarter","Change in NEW credit extended as a percentage of GDP \u2014 the flow of new credit rather than the stock. Leads economic activity by 9-12 months because new borrowing funds current spending","Rate at which banks expand their loan books","Measure of credit availability to small and medium businesses"],"a":1,"e":"Credit impulse: the second derivative of credit (change in new credit flows as % of GDP). Unlike the stock of credit, the impulse reflects how much new borrowing is driving current spending. When credit impulse turns negative, economic activity slows 9-12 months later. China's credit impulse is particularly influential for global growth.","cat":"MACRO","diff":"MD","mod":"Cross-asset","concept":"Credit impulse"},{"q":"What is the shadow banking system?","o":["Illegal and unregulated money lending by criminal organisations","Financial intermediaries (money market funds, repo markets, structured vehicles, broker-dealers) that perform bank-like functions outside traditional banking regulation","Foreign banks operating secretly in a domestic market","Central bank operations conducted off the official balance sheet"],"a":1,"e":"Shadow banking: non-bank financial intermediaries performing bank functions. Examples: money market funds (deposit-like), repo markets (short-term lending), CDOs/SPVs (credit transformation), hedge funds. They grew to $60tn globally. They are vulnerable to runs without deposit insurance or LoLR access \u2014 as seen in 2008.","cat":"MACRO","diff":"VP","mod":"Cross-asset","concept":"Shadow banking"},{"q":"What is the 'Fed pivot' and why do markets obsess over it?","o":["The Fed's annual rotation of regional bank presidents on the FOMC voting committee","The moment the Federal Reserve shifts from a hiking cycle to a cutting cycle \u2014 or signals it is considering doing so \u2014 a turning point that triggers significant cross-asset repricing","A regulatory change in Fed policy on bank capital requirements","The Fed's shift from targeting inflation to targeting employment"],"a":1,"e":"Fed pivot: the transition from tightening to easing. Markets obsess because the Fed's policy rate is the global risk-free rate anchor \u2014 pivots drive repricing across all asset classes simultaneously. A hiking-to-cutting pivot typically triggers: bond rally, equity rally, USD weakness, EM outperformance, gold rally.","cat":"MACRO","diff":"ANALYST","mod":"Central banks","concept":"Fed pivot"},{"q":"What is the debt deflation spiral?","o":["Higher interest rates causing deflation through reduced spending","Self-reinforcing cycle: falling asset prices increase the real burden of debt (deflation raises real debt values), forcing asset sales to repay debt, which depresses prices further \u2014 as described by Irving Fisher (1933)","Government austerity during recession that triggers both debt reduction and deflation","Mechanism by which deflation causes sovereign debt crises in heavily indebted countries"],"a":1,"e":"Irving Fisher's debt deflation (1933): falling prices increase the real value of debt. Debtors sell assets to repay, depressing prices further. More deflation \u2192 higher real debt \u2192 more forced sales \u2192 more deflation. Fisher identified this as the mechanism behind the Great Depression. Japan's lost decade was a mild version.","cat":"MACRO","diff":"MD","mod":"Inflation","concept":"Debt deflation spiral"},{"q":"What are bond vigilantes?","o":["A central bank enforcement mechanism for sovereign bond market participants","Bond market investors who sell government bonds to punish excessive government deficits or inflation \u2014 pushing yields higher and disciplining fiscal policy through market pressure","A regulatory body monitoring bond market manipulation","Activist hedge funds taking large short positions in government bonds"],"a":1,"e":"Bond vigilantes enforce fiscal discipline by selling government bonds when deficits or inflation are deemed excessive \u2014 pushing yields up and forcing the government to tighten. The term was coined in the early 1980s. The UK gilt crisis of 2022 (Truss mini-budget) was a modern bond vigilante episode.","cat":"RATES","diff":"VP","mod":"Cross-asset","concept":"Bond vigilantes"},{"q":"What is dollar dominance and what challenges it?","o":["The US military's global presence underpinning the dollar's reserve status","The dollar's position as dominant global reserve currency, trade invoicing currency, and safe-haven asset \u2014 challenged by US fiscal trajectory, weaponisation (sanctions), China's yuan push, and potential CBDCs","The US Federal Reserve's control over global interest rate cycles","The dominance of US technology companies requiring dollar payments"],"a":1,"e":"Dollar dominance: USD represents ~58% of global reserves, ~90% of FX transactions involve USD, and most commodities are priced in USD. Challenges: US sanctions (weaponising dollar access, Russia 2022 SWIFT exclusion), China's yuan push, US debt trajectory. Most analysts see gradual erosion rather than sudden displacement.","cat":"FX","diff":"VP","mod":"FX mechanics","concept":"Dollar dominance"},{"q":"What is financial repression?","o":["Government crackdowns on speculative financial activity","Government policies keeping real interest rates artificially low (below inflation) to reduce the real value of government debt \u2014 including rate caps, capital controls, forced holdings of government bonds by banks","Excessive banking regulation preventing credit creation","Central bank policies deliberately suppressing asset price volatility"],"a":1,"e":"Financial repression: policies keeping real interest rates negative, eroding the real value of government debt over time. Historically used post-WWII \u2014 the US reduced its 120% debt/GDP through a decade of controlled low rates and moderate inflation. Some argue post-2008 QE and near-zero rates constituted financial repression.","cat":"MACRO","diff":"MD","mod":"Fiscal policy","concept":"Financial repression"},{"q":"What is the Nikkei peak of 1989 and what caused the subsequent crash?","o":["The Nikkei peaked at 38,915 on December 29 1989 due to a speculative bubble in equities and real estate inflated by loose monetary policy; the BOJ's subsequent rate hikes burst the bubble, causing two 'lost decades'","The Nikkei peaked due to the Japanese economic miracle ending as Korea and China became more competitive","The Nikkei peaked on news of the Berlin Wall falling causing euphoria, then crashed due to Cold War spending cuts","The peak was caused by a Ponzi scheme in Japanese corporate bonds that eventually collapsed"],"a":0,"e":"Japan's asset price bubble: ultra-loose monetary policy in the late 1980s inflated equities and real estate to extreme valuations. The Nikkei peaked at 38,915 on December 29 1989. BOJ rate hikes burst the bubble. Japan subsequently experienced two lost decades of deflation, zombie banks, and stagnation \u2014 the definitive case study in liquidity traps.","cat":"EQUITY","diff":"VP","mod":"Historical crises","concept":"Japan bubble 1989"},{"q":"What is the 'taper tantrum' of 2013?","o":["A market overreaction to Fed QE expansion causing excessive bond rallies","The May-June 2013 bond selloff triggered by Fed Chair Bernanke's hint that the Fed might reduce its $85bn/month QE \u2014 causing global bond yields to surge and EM assets to sell off sharply","A central bank coordinated move to reduce all global QE programmes simultaneously","A Treasury market liquidity crisis caused by reduced dealer market-making"],"a":1,"e":"May 2013: Bernanke mentioned QE tapering in congressional testimony. US 10Y yields surged 100bp in weeks. EM economies with current account deficits and dollar-funded borrowing were hardest hit \u2014 the 'Fragile Five' (Brazil, India, Indonesia, South Africa, Turkey). The episode showed how sensitive global markets were to Fed communication.","cat":"RATES","diff":"VP","mod":"Historical crises","concept":"Taper Tantrum 2013"},{"q":"What is Dutch Disease?","o":["A disease affecting tulip crops that caused the 1637 Dutch financial crisis","Economic phenomenon where a large natural resource boom causes currency appreciation that damages other tradeable sectors (manufacturing, non-commodity exports)","A regulatory framework for managing sovereign wealth funds adopted by the Netherlands","Economic contraction caused by excessive government spending on social welfare"],"a":1,"e":"Dutch Disease: named after 1960s Netherlands when North Sea gas discovery caused guilder appreciation, damaging Dutch manufacturing competitiveness. Mechanism: commodity boom \u2192 currency appreciation \u2192 manufacturing uncompetitive \u2192 deindustrialisation \u2192 economy becomes commodity-dependent. Norway's oil fund deliberately keeps oil revenues offshore to prevent this.","cat":"MACRO","diff":"VP","mod":"Balance of payments","concept":"Dutch Disease"},{"q":"What is LIBOR and why was it replaced?","o":["The rate central banks charge commercial banks for overnight loans","The rate at which major banks indicated they could borrow from each other \u2014 used as a benchmark for hundreds of trillions in financial contracts; replaced because it was based on estimates rather than actual transactions and was subject to manipulation (2012 scandal)","The rate set by central bank committees for interbank lending across the Eurozone","The average borrowing cost of the top 20 global banks"],"a":1,"e":"LIBOR (London Interbank Offered Rate): submitted daily by major banks as their unsecured borrowing cost. It underpinned $350tn+ in financial contracts. In 2012, it emerged that banks had manipulated submissions. Additionally, post-2008 interbank unsecured lending dried up \u2014 LIBOR became increasingly theoretical. SOFR replaced USD LIBOR in 2023.","cat":"RATES","diff":"VP","mod":"Money markets","concept":"LIBOR and replacement"},{"q":"What is regulatory arbitrage?","o":["Trading profits earned by exploiting pricing discrepancies between regulated exchanges","Financial institutions restructuring activities to exploit differences in regulations across jurisdictions or between bank and non-bank entities to reduce costs \u2014 a key driver of shadow banking growth","Regulatory bodies competing for oversight of the same institutions","Trading strategies exploiting differences between regulatory and market-implied credit ratings"],"a":1,"e":"Regulatory arbitrage: moving activities to lower-regulation environments to reduce capital requirements, taxes, or restrictions. Post-Basel II, banks moved risk off-balance sheet into structured vehicles (CDOs, SIVs). Post-Dodd Frank, activities migrated to non-bank entities. Regulatory arbitrage drives financial innovation and creates systemic risks in less-regulated spaces.","cat":"MACRO","diff":"MD","mod":"Cross-asset","concept":"Regulatory arbitrage"},{"q":"What is the de-dollarisation trend?","o":["The Federal Reserve's policy of reducing domestic dollar circulation","The gradual shift away from USD as the dominant global reserve, trade, and investment currency \u2014 USD's reserve share declined from 71% (2000) to 58% (2022) but USD remains dominant","The replacement of physical dollar bills by digital dollar (CBDC)","The elimination of dollarisation in countries that previously adopted USD as domestic currency"],"a":1,"e":"De-dollarisation: real but slow. USD's global reserve share fell from 71% (2000) to 58% (2022). Russia's SWIFT exclusion in 2022 accelerated some countries' hedging against dollar weaponisation. China's yuan remains non-convertible, limiting internationalisation. A sudden dollar collapse is unlikely; gradual diversification continues.","cat":"FX","diff":"VP","mod":"FX mechanics","concept":"De-dollarisation"},{"q":"What is 'survivorship bias' and why does it distort our understanding of investment success?","o":["Investors who survive recessions are better informed than those who do not","We only observe and celebrate the winners \u2014 failing traders, funds, and strategies disappear from view, making success look more common and more skill-based than it actually is","Successful investors survive because they have superior information","Markets select for skill over time, so survivors are genuinely more talented"],"a":1,"e":"Survivorship bias (Taleb): cemeteries of failed traders are invisible. We see only the survivors and attribute their success to skill, when many may be lucky. A thousand traders using random strategies will produce a handful of long-term winners \u2014 whose methods we then study and emulate.","cat":"MACRO","diff":"VP","mod":"Probability & Risk","concept":"Survivorship bias"},{"q":"What is Taleb's distinction between 'noise' and 'signal' in financial markets?","o":["Noise is volatility; signal is the underlying trend \u2014 separating them is straightforward with enough data","Short-term market moves are dominated by random noise; longer-term moves contain more signal. Checking a portfolio too frequently means reacting to noise rather than meaningful information","Noise is generated by retail investors; signals by institutional investors","Signal is the news; noise is the market's overreaction to it"],"a":1,"e":"Taleb: the shorter the time horizon of observation, the higher the proportion of noise to signal. A portfolio checked daily shows mostly random variation. Checked yearly, more signal emerges. Frequent monitoring leads to emotional over-trading in response to noise.","cat":"EQUITY","diff":"VP","mod":"Probability & Risk","concept":"Noise vs signal"},{"q":"What does Taleb mean by 'alternative histories'?","o":["The academic study of counterfactual historical scenarios","To evaluate a decision, consider all the outcomes that COULD have occurred given the same decision \u2014 not just the outcome that did occur. A correct outcome does not validate a bad process","The study of how markets would have developed under different regulatory regimes","Alternative explanations for the same historical market event"],"a":1,"e":"Alternative histories: a trader who made money taking excessive risk made a bad decision \u2014 they simply experienced a favourable random draw. The money made does not validate the decision. A sound decision-making process should be evaluated across all possible outcomes it could have produced, not just the realised one.","cat":"MACRO","diff":"MD","mod":"Probability & Risk","concept":"Alternative histories"},{"q":"What is the 'skewness' problem Taleb identifies in trading strategies?","o":["Strategies with positive average returns are always preferable to negative average returns","Some strategies produce small, frequent gains with rare, catastrophic losses \u2014 giving an appearance of skill during good periods, then devastating blowups. The average return may be positive while the expected value (probability-weighted) is negative due to fat-tail losses","Skewness refers to the asymmetric distribution of trading commissions across strategies","Positively skewed strategies always outperform negatively skewed ones"],"a":1,"e":"Skewed strategies (Taleb): selling options or similar strategies produces small regular income but exposes traders to rare, catastrophic losses ('picking up pennies in front of a steamroller'). The historical track record looks excellent until the rare event occurs. Evaluating these strategies requires understanding the full distribution of outcomes, not just recent history.","cat":"EQUITY","diff":"MD","mod":"Probability & Risk","concept":"Strategy skewness and blowup risk"},{"q":"What is the 'black swan problem' as described by Taleb, and how does it relate to risk management?","o":["Rare events that have occurred historically should be given zero weight in risk models","A black swan is a highly improbable, high-impact event that was unpredictable in advance but appears predictable in hindsight \u2014 conventional risk models based on historical data systematically underestimate these tail risks","Risk management should focus exclusively on black swan events and ignore ordinary market volatility","Black swans only affect equity markets; bond and FX markets are immune"],"a":1,"e":"Black swans: unpredictable, high-impact events that are only explained in hindsight. VAR models and normal distribution assumptions (which drove 2008-era risk management) systematically underestimate tail risk because they are calibrated on historical data that excludes unprecedented events. Risk management must account for what has NOT yet happened.","cat":"MACRO","diff":"VP","mod":"Probability & Risk","concept":"Black swan and tail risk"},{"q":"What is 'ergodicity' and why does it matter for understanding investment returns?","o":["Ergodicity means markets return to equilibrium after every shock","A process is ergodic if the average across many parallel paths equals the average over time for a single path. Most financial processes are non-ergodic \u2014 ensemble average returns (across many investors) differ from time-average returns (for a single investor over time). A 50% gain then a 50% loss = -25% despite ensemble average of 0%","Ergodic markets are those where past returns predict future returns","Ergodicity is the property that makes diversification effective"],"a":1,"e":"Ergodicity (Taleb/Peters): a 100% gain then a 50% loss leaves you at 0, despite an ensemble average of +25%. For a single investor, the TIME-average path matters, not the ensemble average. This explains why strategies that look good in ensemble simulations can be ruinous for individual investors following the same path sequentially.","cat":"MACRO","diff":"MD","mod":"Probability & Risk","concept":"Ergodicity in investing"},{"q":"What does Taleb mean by 'hindsight bias' in market analysis?","o":["The tendency for analysts to update their forecasts after events","The cognitive tendency to believe, after an event has occurred, that it was predictable and that one 'knew it all along' \u2014 this leads to overconfidence in forecasting ability and distorts lessons drawn from financial history","The bias of short-term investors toward recent market events","The tendency to overweight recent data relative to historical data"],"a":1,"e":"Hindsight bias: after the 2008 crisis, many claimed they saw it coming. After any crash, explanations appear obvious. This illusion of predictability leads to overconfidence in our ability to forecast the next crisis. Taleb argues that those claiming to have predicted past events rarely have genuine forecasting ability \u2014 they simply got lucky or are selectively remembering.","cat":"MACRO","diff":"VP","mod":"Probability & Risk","concept":"Hindsight bias"},{"q":"What is Papic's 'constraint framework' for geopolitical analysis?","o":["A framework that prioritises leader personalities and intentions as the primary driver of policy outcomes","A framework that focuses on the material constraints facing policymakers \u2014 economic, political, and social \u2014 arguing that constraints are more predictive of policy outcomes than leader personalities or stated intentions","A framework that uses game theory to predict geopolitical outcomes","A quantitative model using historical data to forecast political events"],"a":1,"e":"Papic's constraint framework: policymakers operate within material constraints \u2014 economic (debt levels, growth, FX reserves), political (electoral pressures, coalition dynamics), and social (public opinion, inequality). Even leaders with clear policy intentions will be forced to act within these constraints. Constraints are more predictable and investable than personalities.","cat":"MACRO","diff":"VP","mod":"Geopolitical Alpha","concept":"Constraint framework"},{"q":"What is Papic's distinction between 'geopolitical beta' and 'geopolitical alpha'?","o":["Geopolitical beta is market risk; geopolitical alpha is the extra return from geopolitical research","Geopolitical beta is the systematic, general geopolitical environment affecting all assets; geopolitical alpha is the specific, investable insight derived from correctly forecasting a particular geopolitical outcome that markets have mispriced","Beta refers to developed market geopolitics; alpha to EM geopolitics","Geopolitical beta is short-term and alpha is long-term geopolitical risk"],"a":1,"e":"Papic: geopolitical beta is the general risk environment \u2014 elevated tensions, uncertainty \u2014 which markets price broadly. Geopolitical alpha comes from correctly forecasting a SPECIFIC geopolitical outcome (election result, policy change, treaty outcome) that the market has priced incorrectly, generating a genuine investment edge.","cat":"MACRO","diff":"MD","mod":"Geopolitical Alpha","concept":"Geopolitical beta vs alpha"},{"q":"According to Papic, why do geopolitical events often fail to cause lasting market dislocations?","o":["Markets are efficient and always correctly price geopolitical risk","Most geopolitical events represent tail risks that rarely materialise \u2014 markets habitually overreact to geopolitical noise, creating opportunities for investors with a framework to distinguish geopolitical noise from genuine signal","Geopolitical events only affect emerging markets, not developed market assets","Central bank intervention consistently offsets geopolitical market disruption"],"a":1,"e":"Papic: markets systematically overreact to geopolitical events because they treat every event as potentially transformative. Most geopolitical tensions resolve without lasting economic impact. An investor with a constraint-based framework can identify which geopolitical events represent genuine systemic risk versus which are noise that will revert \u2014 generating alpha by fading overreactions.","cat":"MACRO","diff":"VP","mod":"Geopolitical Alpha","concept":"Geopolitical market overreaction"},{"q":"What does Papic's framework suggest about the relationship between policymaker intentions and market outcomes?","o":["Leaders with clear policy intentions always successfully implement their agenda \u2014 intentions are the best predictor of outcomes","Policymaker intentions are poor predictors of outcomes because material constraints (economic reality, coalition politics, market discipline) override intentions. Even populist leaders tend to moderate when facing binding economic constraints","Market outcomes are determined entirely by structural economic forces, making political analysis irrelevant","Only authoritarian leaders face genuine constraints; democratic leaders can implement any agenda"],"a":1,"e":"Papic: 'policy is the art of the possible.' Even the most anti-market, populist leaders face constraints \u2014 currency crises, bond market selloffs, IMF conditionality, coalition defections. The constraint framework predicts that most radical policy intentions moderate when they encounter binding material reality. This was demonstrated repeatedly in EM history (Argentina, Turkey, Brazil).","cat":"MACRO","diff":"VP","mod":"Geopolitical Alpha","concept":"Intentions vs constraints in policy"},{"q":"How does Papic's framework apply to understanding the 2022 Russian invasion of Ukraine and its market impact?","o":["The invasion demonstrates that all geopolitical events cause permanent market dislocations","The invasion illustrates constraints on both sides: Russia constrained by sanctions and economic isolation; Europe constrained by energy dependence; neither side unconstrained in their objectives. Market impact was real but contained compared to initial fears of systemic contagion","Papic's framework predicted the invasion would have no market impact","The invasion proves that geopolitical events always cause lasting commodity price changes"],"a":1,"e":"Applying the constraint framework to Ukraine: Russia's constraint (energy revenues, reserve drain) vs Europe's constraint (energy dependence, political will). The framework helps distinguish between initial risk-off overreaction and genuine structural shifts. European energy diversification was a constrained choice \u2014 not a free one. Markets eventually priced the new equilibrium rather than sustained escalation.","cat":"MACRO","diff":"MD","mod":"Geopolitical Alpha","concept":"Constraint framework applied to geopolitical events"},{"q":"What was the fundamental disagreement between Keynes and Harry White at Bretton Woods in 1944?","o":["Keynes wanted to keep the gold standard; White wanted to abolish it entirely","Keynes wanted a new global currency (Bancor) and adjustment burden shared between surplus and deficit countries; White wanted the USD at the centre, with deficit countries bearing all adjustment costs \u2014 reflecting US creditor interests","Keynes wanted fixed exchange rates; White wanted floating rates","Keynes wanted the IMF based in London; White insisted on Washington"],"a":1,"e":"The Bretton Woods divide: Keynes proposed Bancor (a new international currency) with symmetric adjustment \u2014 surplus countries (the US) would pay interest on excess reserves, sharing the burden. White, representing a creditor US, insisted on a dollar-centric system where deficit countries bore all adjustment pressure. White's plan won, establishing the USD-based Bretton Woods system.","cat":"FX","diff":"VP","mod":"Bretton Woods","concept":"Keynes vs White at Bretton Woods"},{"q":"What was Keynes's 'Bancor' proposal and why was it rejected?","o":["A new British currency to replace the pound sterling after WWII","A proposed supranational reserve currency managed by an international clearing union \u2014 deficit countries would borrow and surplus countries would pay interest on excess balances, creating symmetric adjustment pressure. Rejected because the US (the dominant surplus nation) refused to accept adjustment obligations","A proposal to return to the gold standard with a new reserve currency","A plan for European monetary union proposed by Keynes in 1944"],"a":1,"e":"Bancor: Keynes proposed an international clearing union issuing 'bancor' \u2014 countries would hold accounts in bancor. Deficit countries would pay interest (incentive to adjust); surplus countries would ALSO pay interest on excess bancor (incentive for surplus countries to reduce surpluses). The US rejected this because it would have obligated the US as a surplus nation to stimulate imports and reduce its creditor advantage.","cat":"FX","diff":"MD","mod":"Bretton Woods","concept":"Bancor proposal"},{"q":"What was the 'Triffin Dilemma' that emerged from the Bretton Woods system?","o":["The conflict between Keynes and White over exchange rate flexibility","The fundamental contradiction: the US had to run current account deficits to supply the world with dollars for trade and reserves, but persistent deficits eventually undermined confidence in the dollar's gold convertibility \u2014 the system was structurally self-undermining","The dilemma faced by the IMF in balancing the interests of member nations","The problem of financing US military spending in Europe under fixed exchange rates"],"a":1,"e":"Triffin Dilemma (Robert Triffin, 1960): Bretton Woods required the US to run persistent deficits to supply the world with dollars. But as dollar holdings abroad grew and exceeded US gold reserves, confidence in dollar-gold convertibility eroded. The system required the US to behave in a way that would eventually destroy its credibility \u2014 a structural flaw leading to the 1971 Nixon shock.","cat":"FX","diff":"VP","mod":"Bretton Woods","concept":"Triffin Dilemma"},{"q":"What was the 'Nixon Shock' of August 1971?","o":["President Nixon imposed wage and price controls to fight inflation","President Nixon announced the closing of the gold window \u2014 ending the Bretton Woods system's convertibility of dollars into gold at $35/oz \u2014 effectively abandoning the post-WWII monetary order and ushering in the era of floating exchange rates","Nixon's imposition of a 10% import surcharge on all imports to improve the trade balance","Nixon's decision to float the dollar against European currencies in response to speculative pressure"],"a":1,"e":"Nixon Shock (August 15, 1971): Nixon announced the US would no longer convert dollars to gold at $35/oz, effectively ending the Bretton Woods system. The dollar could no longer be redeemed for gold. This ended the gold exchange standard and ushered in the modern era of floating exchange rates. The decision was driven by persistent US trade deficits and the drain on US gold reserves.","cat":"FX","diff":"VP","mod":"Bretton Woods","concept":"Nixon shock 1971"},{"q":"Why was the IMF initially dominated by the United States despite being a multilateral institution?","o":["The US provided the most experienced economists for IMF management","Voting rights were allocated proportional to member quotas (capital contributions), and the US held the largest quota \u2014 giving it effective veto power over major IMF decisions. This was a direct outcome of Harry White's design privileging the dominant creditor nation","The US was the only country with sufficient gold reserves to fund IMF operations","The UN Security Council structure was replicated in the IMF governance framework"],"a":1,"e":"IMF governance: voting rights are proportional to quotas (capital contributions). The US, as the dominant creditor in 1944, received the largest quota and effective veto power. Harry White designed the institution to reflect US interests \u2014 ensuring the US could block any decision it opposed. This structure reflected and reinforced the dollar's central role in the post-war monetary system.","cat":"FX","diff":"VP","mod":"Bretton Woods","concept":"IMF governance and US veto"},{"q":"What is the Special Drawing Right (SDR) and how did it emerge from the Bretton Woods system's structural problems?","o":["The SDR is a floating exchange rate mechanism created by the Nixon administration","The SDR is an international reserve asset created by the IMF in 1969 to supplement dollar reserves \u2014 emerging from recognition that the system was running short of non-dollar reserve assets as global trade grew, but the US could not run unlimited deficits to supply enough dollars","The SDR is a development finance mechanism for emerging market countries","The SDR was created as a replacement for gold in the Bretton Woods system"],"a":1,"e":"SDRs (Special Drawing Rights): created by the IMF in 1969 as a partial response to the Triffin Dilemma. As global trade grew, the world needed more reserve assets, but relying solely on US deficits was unsustainable. SDRs were created as a supplementary reserve asset allocated to member countries. They are not a currency and cannot be used for private transactions \u2014 but represent IMF drawing rights.","cat":"FX","diff":"MD","mod":"Bretton Woods","concept":"Special Drawing Rights"},{"q":"What was Samuelson's central critique of pure laissez-faire economics and how did he reconcile it with market efficiency?","o":["Samuelson believed markets were always efficient and needed no government intervention","Samuelson argued markets have systematic failures (externalities, public goods, information asymmetries, monopolies) requiring corrective government policy \u2014 but this does not negate the power of markets for most resource allocation. Mixed economy synthesis: use markets where they work, correct failures where they don't","Samuelson was a Marxist economist who rejected market mechanisms entirely","Samuelson argued that all economic problems could be solved through central planning"],"a":1,"e":"Samuelson's neoclassical synthesis: markets are powerful allocation mechanisms but fail systematically in certain cases. Externalities (pollution), public goods (national defence), information asymmetries (insurance markets), and monopoly power require government correction. This 'mixed economy' framework \u2014 combining market efficiency with targeted intervention \u2014 became the foundation of mainstream post-WWII economics.","cat":"MACRO","diff":"VP","mod":"Economic thought","concept":"Samuelson's neoclassical synthesis"},{"q":"What did Volcker explain, in his interview, as the key mechanism by which high interest rates defeated the 1970s inflation?","o":["High rates directly reduced the money supply by making borrowing unaffordable","High rates worked primarily by creating enough slack in the economy (recession, unemployment) to break the wage-price spiral and credibly signal that the Fed would not accommodate inflation \u2014 restoring the anchor for inflation expectations","Volcker believed the primary mechanism was reducing government deficits through higher debt service costs","High rates worked by attracting foreign capital which appreciated the dollar and reduced import prices"],"a":1,"e":"Volcker's mechanism: high rates induced recession and unemployment (10.8%), which broke workers' ability to demand inflation-compensating wages \u2014 interrupting the wage-price spiral. But the deeper mechanism was credibility: by accepting severe short-term pain, the Fed demonstrated it would not accommodate inflation, permanently anchoring expectations downward. Credibility, once established, required less ongoing rate pressure.","cat":"MACRO","diff":"VP","mod":"Economic thought","concept":"Volcker disinflation mechanism"},{"q":"What is 'rational expectations' theory and how did it challenge Keynesian demand management?","o":["The theory that all economic agents make correct forecasts on average","The theory that economic agents form expectations using all available information efficiently \u2014 implying that anticipated monetary or fiscal policy will be fully anticipated and priced in, making systematic demand management ineffective. Only surprise policy works, but surprises cannot be systematically achieved","The theory that markets are always in equilibrium and policy cannot affect real outcomes","The theory that expectations about inflation are always anchored at the central bank's target"],"a":1,"e":"Rational expectations (Lucas, Sargent): if agents use all available information to forecast policy, anticipated stimulus will be neutralised by immediate expectation adjustments. Only unanticipated policy affects real variables. This challenged Keynesian demand management \u2014 systematic policy cannot systematically stimulate because people will anticipate it. It led to the 'policy ineffectiveness proposition' and reinforced the importance of central bank credibility.","cat":"MACRO","diff":"MD","mod":"Economic thought","concept":"Rational expectations"},{"q":"According to Milton Friedman's famous maxim discussed by Samuelson, what is the fundamental cause of inflation?","o":["Inflation is caused by supply chain disruptions and cost-push factors","Inflation is always and everywhere a monetary phenomenon \u2014 sustained inflation requires sustained money supply growth in excess of real output growth","Inflation is caused by excessive government spending financed by bond issuance","Inflation is primarily determined by oil prices and commodity supply shocks"],"a":1,"e":"Friedman's dictum: 'Inflation is always and everywhere a monetary phenomenon.' Sustained inflation cannot occur without sustained money growth above real output growth \u2014 because prices are ultimately determined by the quantity of money relative to output. Supply shocks can cause one-time price level rises, but cannot cause sustained inflation without accommodating monetary expansion.","cat":"MACRO","diff":"ANALYST","mod":"Economic thought","concept":"Friedman's monetary theory of inflation"},{"q":"What is the 'Lucas critique' and how did it change macroeconomic modelling?","o":["Lucas argued that econometric models should use more historical data","The critique that historical policy relationships (estimated from past data) break down when policy changes \u2014 because agents change their behaviour in response to new policy regimes, invalidating models built on old behavioural patterns. Policy evaluation requires models of deep structural parameters that are invariant to policy changes","Lucas argued that government policy was always ineffective and should be abandoned","The critique that econometric models are too complex and should be simplified"],"a":1,"e":"Lucas critique (1976): if the Fed uses a historical relationship (e.g. Phillips Curve) to guide policy, agents will alter their behaviour in response to the new policy, changing the relationship. Historical correlations are not structural parameters. This insight pushed macro towards DSGE models with microfoundations \u2014 estimated structural parameters that should be invariant to policy changes.","cat":"MACRO","diff":"MD","mod":"Economic thought","concept":"Lucas critique"},{"q":"What is Okun's Law?","o":["A 1% rise in inflation reduces unemployment by 2%","A 1 percentage point rise in the unemployment rate above the natural rate corresponds to roughly a 2% fall in actual GDP relative to potential GDP","Higher interest rates reduce unemployment proportionally","Government spending increases output by a multiple of the initial expenditure"],"a":1,"e":"Okun's Law (Arthur Okun, 1962): each 1pp of cyclical unemployment above the natural rate is associated with approximately 2% of GDP lost relative to potential. It links the labour market to the output gap, giving central banks a rough guide to the economic cost of unemployment.","cat":"MACRO","diff":"VP","mod":"Labor markets","concept":"Okun's Law"},{"q":"What is the national saving identity in a closed economy?","o":["National saving equals consumption plus investment","National saving equals investment \u2014 all saving in a closed economy must be channelled into domestic investment through financial markets","National saving equals GDP minus taxes","National saving equals government revenue minus spending"],"a":1,"e":"In a closed economy (no foreign trade): GDP = C + I + G. National saving (S) = GDP - C - G = I. All domestic saving must equal domestic investment by accounting identity. This identity underpins the Keynesian multiplier and the crowding-out debate.","cat":"MACRO","diff":"ANALYST","mod":"GDP","concept":"National saving identity"},{"q":"What is the difference between private saving and public saving?","o":["Private saving is by households; public saving is by corporations","Private saving = disposable income minus consumption. Public saving = tax revenue minus government expenditure (the budget surplus). National saving = private + public saving","Private saving is invested in stocks; public saving in bonds","Private saving is short-term; public saving is long-term"],"a":1,"e":"Private saving: Y - T - C (income after taxes minus consumption). Public saving: T - G (taxes minus government spending = budget surplus). A budget deficit means negative public saving, which reduces national saving and (in a closed economy) domestic investment \u2014 the mechanism of crowding out.","cat":"MACRO","diff":"VP","mod":"Fiscal policy","concept":"Private vs public saving"},{"q":"What is the natural rate of unemployment?","o":["The unemployment rate when all workers who want jobs have them","The rate of unemployment consistent with stable inflation \u2014 comprising frictional (job search) and structural (skills mismatch) unemployment but not cyclical unemployment","The lowest unemployment rate ever achieved in a country's history","The unemployment rate targeted by the central bank's monetary policy"],"a":1,"e":"The natural rate of unemployment (Friedman/Phelps): the rate consistent with stable inflation, comprising frictional unemployment (short-term job search) and structural unemployment (skills/location mismatch). Cyclical unemployment is the difference between actual and natural rate. The natural rate is unobservable and changes over time.","cat":"MACRO","diff":"VP","mod":"Labor markets","concept":"Natural rate of unemployment"},{"q":"What is frictional unemployment and why does it exist even in healthy economies?","o":["Unemployment caused by economic recessions and insufficient demand","Unemployment arising from the time it takes workers to search for and match with new jobs \u2014 exists because labour markets have imperfect information and matching takes time, even in a strong economy","Unemployment caused by structural changes making certain skills obsolete","Unemployment among workers who have given up searching for work"],"a":1,"e":"Frictional unemployment is the temporary unemployment of workers transitioning between jobs or entering the labour market. It exists because job matching takes time \u2014 workers and employers need to find each other and assess fit. It is a normal and even healthy feature of a flexible labour market. Lower frictional unemployment can indicate poor labour market dynamism.","cat":"MACRO","diff":"ANALYST","mod":"Labor markets","concept":"Frictional unemployment"},{"q":"What is the aggregate demand/aggregate supply (AD/AS) model's key prediction about the long run?","o":["In the long run, higher government spending permanently raises real GDP","In the long run, the price level adjusts so real GDP returns to potential output regardless of aggregate demand shifts \u2014 monetary neutrality holds in the long run","In the long run, higher inflation permanently reduces unemployment via the Phillips Curve","In the long run, technological change is the only determinant of economic growth"],"a":1,"e":"AD/AS model: in the long run, the aggregate supply curve is vertical at potential output (LRAS). Demand shocks shift AD, causing short-run output deviations, but prices adjust until real GDP returns to potential. This long-run neutrality of money means central banks cannot permanently raise real output by increasing demand \u2014 only short-run effects are possible.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"Long-run aggregate supply"},{"q":"What is Ricardian equivalence and what does it imply for fiscal stimulus?","o":["The observation that government bonds and equities produce equivalent returns over time","The proposition that deficit-financed tax cuts have no effect on consumption because rational households save the tax cut to pay future taxes \u2014 fiscal stimulus via tax cuts is neutralised","The theorem that all government spending eventually pays for itself through higher growth","The principle that fiscal and monetary policy are interchangeable in their economic effects"],"a":1,"e":"Ricardian equivalence (David Ricardo/Robert Barro): rational, forward-looking households who receive a tax cut understand that future taxes must rise to repay the deficit. They save the entire tax cut to pay future taxes, leaving consumption unchanged. If true, deficit-financed tax cuts have zero stimulative effect. In practice, it fails partially \u2014 some households are liquidity-constrained and do spend tax cuts.","cat":"MACRO","diff":"MD","mod":"Fiscal policy","concept":"Ricardian equivalence"},{"q":"What is the 'crowding out' mechanism and when is it most severe?","o":["When government regulation prevents private firms from entering markets","When government borrowing raises real interest rates, reducing private investment \u2014 most severe when the economy is near full capacity and financial markets are tight","When inflation erodes business profits preventing new investment","When imports displace domestic production reducing business investment"],"a":1,"e":"Crowding out: government borrowing increases demand for loanable funds, pushing up real interest rates, reducing private investment. Most severe when: (1) the economy is at full capacity (no spare resources to absorb government demand), (2) government debt is already high (higher risk premium), and (3) private investment is interest-rate sensitive. Least severe during deep recessions when private demand is weak.","cat":"MACRO","diff":"VP","mod":"Fiscal policy","concept":"Crowding out"},{"q":"What is the multiplier effect of government spending and what determines its size?","o":["Government spending multiplies because the government is more efficient than the private sector","An initial increase in government spending generates a larger total increase in GDP as recipients re-spend income \u2014 the multiplier is larger when the marginal propensity to consume is higher and leakages (taxes, imports, saving) are smaller","Government spending always multiplies by exactly 2 times the initial amount","The multiplier is always greater than 1 regardless of economic conditions"],"a":1,"e":"The Keynesian multiplier: initial government spending generates income, which is partially re-spent, generating more income. Multiplier = 1/(1-MPC) in a simple model, but reduced by tax leakages, import leakages, and savings. In open economies with high imports, the multiplier is small. In recessions with high idle capacity, it is larger. In normal times with crowding out, it may be below 1.","cat":"MACRO","diff":"VP","mod":"Fiscal policy","concept":"Government spending multiplier"},{"q":"What is the difference between the short-run and long-run Phillips Curve?","o":["There is no difference \u2014 the Phillips Curve is the same in both time horizons","The short-run Phillips Curve shows a trade-off between inflation and unemployment; the long-run curve is vertical at the natural rate \u2014 higher expected inflation shifts the short-run curve upward, eliminating any permanent trade-off","The long-run Phillips Curve slopes downward more steeply than the short-run curve","In the long run, higher unemployment always leads to lower inflation"],"a":1,"e":"Friedman-Phelps expectations-augmented Phillips Curve: the short-run trade-off between inflation and unemployment holds only for unexpected inflation. When workers adjust expectations upward, the short-run curve shifts up \u2014 the same unemployment now comes with higher inflation. In the long run, the curve is vertical at the natural rate \u2014 no permanent trade-off exists.","cat":"MACRO","diff":"VP","mod":"Inflation","concept":"Short vs long-run Phillips Curve"},{"q":"What is the IS curve in the IS-LM model?","o":["The curve showing combinations of interest rates and output where the goods market is in equilibrium (investment = saving)","The curve showing combinations where money supply equals money demand","The curve showing combinations of inflation and output consistent with monetary policy","The curve showing the interest rate the central bank sets at each level of GDP"],"a":0,"e":"IS curve (Investment-Saving): shows combinations of interest rate and output (GDP) where the goods market is in equilibrium \u2014 planned expenditure equals actual output, or equivalently, investment equals saving. The IS curve slopes downward: lower interest rates stimulate investment and consumption, raising equilibrium output. Fiscal policy shifts the IS curve.","cat":"MACRO","diff":"MD","mod":"Monetary policy","concept":"IS curve"},{"q":"What is the LM curve in the IS-LM model?","o":["The curve showing combinations of interest rates and output where the goods market is in equilibrium","The curve showing combinations of interest rates and output where the money market is in equilibrium \u2014 money supply equals money demand","The curve showing the central bank's reaction function","The curve showing long-run monetary neutrality"],"a":1,"e":"LM curve (Liquidity-Money): shows combinations of interest rate and output where money demand equals money supply. It slopes upward \u2014 higher output increases money demand, pushing up interest rates. Monetary policy shifts the LM curve: increasing money supply shifts LM right, lowering rates at each output level. Modern central banks set interest rates directly, replacing the LM with a monetary policy rule.","cat":"MACRO","diff":"MD","mod":"Monetary policy","concept":"LM curve"},{"q":"What is the concept of 'potential output' (or potential GDP)?","o":["The maximum GDP a country has ever achieved","The level of GDP the economy would produce if all resources (labour and capital) were fully employed at their normal utilisation rates \u2014 also called full-employment GDP","The GDP predicted by economic forecasters for the next year","The GDP level at which there is zero unemployment of any kind"],"a":1,"e":"Potential output is the GDP produced when unemployment equals the natural rate and capital is at normal utilisation \u2014 the economy's 'speed limit'. Actual GDP fluctuates around potential. A negative output gap (actual < potential) signals disinflationary pressure; positive gap signals inflationary pressure. Central banks monitor the output gap to set policy.","cat":"MACRO","diff":"VP","mod":"GDP","concept":"Potential output"},{"q":"What is structural unemployment and what policies address it?","o":["Unemployment during economic recessions caused by insufficient aggregate demand","Unemployment arising from a mismatch between the skills workers have and the skills employers need \u2014 often caused by technological change, automation, or shifts in demand for industries","Unemployment caused by seasonal variations in labour demand","Unemployment among workers moving between regions of a country"],"a":1,"e":"Structural unemployment arises when the structure of the economy changes \u2014 automation eliminating roles, industries declining, or skills becoming obsolete. Workers whose skills no longer match available jobs face structural unemployment. Addressed by: job retraining programmes, education investment, relocation assistance. Monetary policy cannot fix structural unemployment \u2014 it requires supply-side interventions.","cat":"MACRO","diff":"VP","mod":"Labor markets","concept":"Structural unemployment"},{"q":"What does Bernanke's analysis of the Great Depression identify as the key mechanism that turned a recession into a depression?","o":["Excessive government spending that crowded out private investment","Banking system collapse disrupted credit intermediation \u2014 the bank failures of 1930-33 destroyed the financial channel linking savings to borrowers, causing a credit crunch that amplified and prolonged the downturn far beyond a normal recession","The gold standard prevented monetary expansion needed to stop deflation \u2014 though the credit channel was the key amplification mechanism","Protectionist trade policies (Smoot-Hawley) reduced global trade sufficiently to cause the depression"],"a":1,"e":"Bernanke's key insight (his academic work): the Great Depression was amplified by the destruction of credit intermediation through bank failures. Banks have specialised knowledge about borrowers \u2014 when they fail, that information is lost. The surviving credit shortage prevented normal recovery. This 'credit channel' insight shaped Bernanke's Fed response in 2008: prevent bank failures to preserve credit intermediation.","cat":"MACRO","diff":"MD","mod":"Historical crises","concept":"Bernanke - Great Depression and credit channel"},{"q":"What is a Credit Linked Note (CLN)?","o":["A government bond with a floating rate linked to credit ratings","A structured note embedding a credit default swap \u2014 the investor accepts credit risk on a reference entity in exchange for a higher coupon; if the reference entity defaults, the investor loses principal proportionally","A bond issued by an SPV backed by mortgage loans","A note where the coupon adjusts based on the issuer's own credit spread"],"a":1,"e":"A CLN packages a bond with an embedded CDS. The investor receives enhanced yield in exchange for bearing credit risk on a reference entity. If a credit event (default, restructuring) occurs, the investor receives recovery value instead of par. CLNs allow banks to transfer credit risk off balance sheet while giving investors synthetic credit exposure in funded note format.","cat":"RATES","diff":"VP","mod":"Structured Products","concept":"Credit Linked Note"},{"q":"What is a Dual Currency Deposit (DCD)?","o":["A bank account denominated in two currencies simultaneously","A short-term deposit paying enhanced yield in exchange for giving the bank the right to repay principal in a different currency at a pre-agreed rate if the reference currency moves past the strike","A fixed income instrument paying coupons in two currencies alternately","A deposit linked to two central bank interest rates"],"a":1,"e":"A DCD pays above-market interest because the investor sells an FX option to the bank. If the reference currency moves beyond the strike, the bank repays in the weaker currency at the agreed rate \u2014 potentially giving the investor less in their home currency. Popular for HNW clients with genuine currency flexibility and a medium-term market view.","cat":"FX","diff":"VP","mod":"Structured Products","concept":"Dual Currency Deposit"},{"q":"What is an autocallable structured note?","o":["A bond that automatically calls if interest rates fall below a trigger","A structured product that automatically redeems early at par plus a coupon if the underlying is above a barrier on observation dates \u2014 otherwise continues until maturity with potential capital loss below a lower barrier","A callable bond where the issuer always exercises on the first call date","A note that converts to equity if the issuer's credit deteriorates"],"a":1,"e":"Autocallables offer enhanced coupons and early redemption if the underlying (equity index, single stock) stays above the autocall barrier on periodic observation dates. If the underlying falls below a capital protection barrier at maturity, investors lose principal proportionally. They offer yield above bonds in exchange for equity downside risk and potential early redemption removing upside participation.","cat":"EQUITY","diff":"VP","mod":"Structured Products","concept":"Autocallable structured note"},{"q":"What is a barrier option and why is it used in structured products?","o":["An option only exercisable on specific calendar dates","An option that activates (knock-in) or deactivates (knock-out) when the underlying crosses a price level \u2014 used to cheapen structured product hedges by reducing option cost versus vanilla equivalents","An option whose payoff is the difference between two asset prices","An option whose premium is paid in installments"],"a":1,"e":"Barrier options are path-dependent: knock-outs expire worthless if the underlying crosses the barrier (reducing cost vs vanilla); knock-ins only become active if the barrier is crossed. In structured products, down-and-in puts provide capital protection cheaply because they only activate when markets have already fallen sharply \u2014 by which point the barrier serves as a floor on further loss participation.","cat":"EQUITY","diff":"MD","mod":"Structured Products","concept":"Barrier options in structured products"},{"q":"What is a CLO (Collateralised Loan Obligation)?","o":["A bond backed by a pool of residential mortgages sliced into tranches","A structured vehicle that pools leveraged loans and issues tranched securities \u2014 senior AAA tranches receive first claim on cash flows; junior equity tranches absorb losses first but earn higher yields","A central bank lending facility providing collateralised loans to commercial banks","A government programme collateralised by state assets"],"a":1,"e":"CLOs buy portfolios of leveraged loans and issue tranches from AAA (low yield, protected by subordination) to equity (unrated, first-loss, highest yield). The CLO manager actively trades the loan portfolio within guidelines. CLOs are the primary buyers of leveraged loans globally and grew dramatically post-2008 as bank loan-holding capacity fell under Basel III capital rules.","cat":"RATES","diff":"MD","mod":"Structured Products","concept":"CLO mechanics"},{"q":"What is vega risk and why does it matter for structured product issuers?","o":["Sensitivity of option price to the underlying asset price","Sensitivity of an option's price to changes in implied volatility \u2014 structured product issuers who sell options embedded in notes are short vega; when market volatility spikes unexpectedly, their option positions lose value","Sensitivity of option price to changes in interest rates","Time decay of an option's value as it approaches expiry"],"a":1,"e":"Vega measures how much an option price changes per 1% move in implied volatility. Structured product desks sell options to fund enhanced coupons, making them short vega. When market volatility spikes (risk-off events), short vega positions lose money. Managing aggregate vega exposure \u2014 through buying vol or offsetting with other structures \u2014 is a core risk management challenge on structured product desks.","cat":"EQUITY","diff":"MD","mod":"Structured Products","concept":"Vega risk in structured products"},{"q":"What is a Uridashi bond?","o":["A Japanese government bond sold exclusively to foreign central banks","A foreign currency denominated bond issued by non-Japanese entities and sold to Japanese retail investors \u2014 exploiting Japanese investors' demand for yield above near-zero JGB rates","A bond issued by Japanese corporations in foreign markets","A Japanese municipal bond backed by local government revenues"],"a":1,"e":"Uridashi bonds: foreign-currency bonds (typically AUD, NZD, ZAR) issued by foreign sovereigns or supranationals and distributed to Japanese retail investors through domestic channels. They exploit the gap between near-zero Japanese rates and higher foreign yields. AUD/NZD Uridashi flows historically supported these currencies and were an important driver of Japanese retail investor FX behaviour.","cat":"FX","diff":"VP","mod":"Japan Markets","concept":"Uridashi bonds"},{"q":"What is FIEA and why does it matter for financial product distribution in Japan?","o":["Japan's banking regulation governing commercial lending","Japan's comprehensive securities law (\u91d1\u878d\u5546\u54c1\u53d6\u5f15\u6cd5) governing financial instruments, exchanges, and investment advisers \u2014 including registration requirements, disclosure rules, and conduct standards (suitability) for derivatives and structured product sales","Japan's foreign exchange control law governing cross-border capital flows","Japan's corporate governance code for listed companies"],"a":1,"e":"FIEA (Financial Instruments and Exchange Act, enacted 2007): governs financial instruments business registration, disclosure requirements, insider trading rules, and suitability assessment for complex products. Any institution distributing structured products, derivatives, or investment trusts in Japan must be registered under FIEA, maintain proper conduct standards, and document suitability assessments \u2014 critical compliance framework for foreign banks operating in Japan.","cat":"MACRO","diff":"MD","mod":"Japan Markets","concept":"FIEA framework"},{"q":"Why has the Bank of Japan maintained ultra-loose policy for decades?","o":["The BOJ is legally prohibited from raising rates above zero","Japan's experience with deflation, weak growth, and government debt at 260% of GDP made the BOJ extremely reluctant to tighten \u2014 fearing deflation resurface, government debt costs to spike, and fragile growth to collapse","The BOJ has no mandate to consider inflation, only exchange rate stability","Japanese export competitiveness permanently requires near-zero rates"],"a":1,"e":"BOJ ultra-loose policy reflects multiple binding constraints: (1) deflation experience since the 1990s created deep institutional caution about premature tightening; (2) government debt at ~260% of GDP means even modest rate rises dramatically increase debt servicing costs; (3) weak domestic demand required ongoing stimulus. The BOJ's eventual rate normalisation from 2024 reflected inflation finally becoming durable after 30 years.","cat":"MACRO","diff":"VP","mod":"Japan Markets","concept":"BOJ persistent ultra-loose policy rationale"},{"q":"What is the 'Tokkin' investment vehicle used by Japanese institutional investors?","o":["A Bank of Japan emergency lending facility for distressed institutions","A discretionary investment trust (\u7279\u5b9a\u91d1\u5916\u4fe1\u8a17) used by Japanese corporates and institutional investors to outsource asset management \u2014 banks manage assets within agreed guidelines, used for bond portfolios and sometimes structured product access","A Japanese pension fund structure regulated by the Ministry of Finance","A government special account for managing foreign exchange reserves"],"a":1,"e":"Tokkin (\u7279\u5b9a\u91d1\u5916\u4fe1\u8a17): discretionary trust arrangement where Japanese corporates and institutional investors delegate investment management to a bank within agreed parameters. Historically important for equity holdings; now used for managing bond and structured product portfolios. In the structured products context, Tokkin structures provide institutional clients access to complex payoffs while maintaining clear fiduciary documentation \u2014 important in Japan's relationship-based financial system.","cat":"MACRO","diff":"MD","mod":"Japan Markets","concept":"Tokkin vehicle"},{"q":"What is the significance of the BOJ's 'yield curve control' abandonment in 2024?","o":["The BOJ expanded YCC to include corporate bonds as well as JGBs","The BOJ phased out its 10Y JGB yield cap (YCC), raised the policy rate above zero for the first time since 2007, and began a genuine monetary policy normalisation \u2014 marking the end of Japan's multi-decade experiment with ultra-loose policy and creating significant JPY volatility and global bond market implications","The BOJ abolished all bond purchases to allow yields to find their natural level","The BOJ transferred YCC responsibility to the Japanese government"],"a":1,"e":"BOJ YCC exit (2024): as Japanese inflation durably exceeded 2% for the first time in decades, the BOJ raised rates above zero and removed the YCC cap on 10Y JGBs. This ended an era of engineered low yields and had global implications: Japanese investors who had been forced offshore by low domestic yields had reason to repatriate capital, affecting JGB yields, JPY, and yields of the US/European bonds they had been buying.","cat":"RATES","diff":"VP","mod":"Japan Markets","concept":"BOJ YCC exit 2024"},{"q":"What is Value at Risk (VaR) and its key limitation?","o":["VaR measures the maximum possible loss under any scenario","VaR estimates the maximum loss over a given horizon at a specified confidence level (e.g. 99% 1-day VaR) \u2014 the key limitation is that it says nothing about the size of losses beyond the threshold, and assumes historical correlations hold during crises","VaR measures the average loss during all market downturns over 5 years","VaR is a complete risk measure that captures all financial risks perfectly"],"a":1,"e":"VaR (e.g. 99% 1-day): 'we won't lose more than $X on 99% of trading days.' Critical limitation: it tells you nothing about the magnitude of the 1% tail losses. A strategy with $10M VaR could lose $11M or $500M in the tail \u2014 VaR doesn't distinguish. Additionally, VaR is based on historical correlations that collapse during crises, and assumes return distributions are normal \u2014 understating fat-tail risk. Expected Shortfall (ES) addresses the tail limitation.","cat":"MACRO","diff":"VP","mod":"Risk Management","concept":"VaR and its limitations"},{"q":"What is wrong-way risk in derivatives?","o":["The risk that a derivative moves against you due to model errors","Wrong-way risk: counterparty credit quality deteriorates at exactly the same time as the derivative exposure increases \u2014 creating compounded losses because the counterparty most likely to default is also the one that owes you the most","The risk that settlement fails when a derivative has significant value","The risk that a counterparty exercises an option at the worst possible time for you"],"a":1,"e":"Wrong-way risk (WWR): when there is adverse correlation between counterparty credit quality and your exposure to them. Example: buying a put on bank stocks from a bank counterparty \u2014 the put's value increases when banks are stressed, exactly when your counterparty is most likely to default. WWR was a major amplifier in 2008. Management requires scenario analysis and careful selection of which products to trade with which counterparties.","cat":"RATES","diff":"MD","mod":"Risk Management","concept":"Wrong-way risk"},{"q":"What is CVA (Credit Valuation Adjustment)?","o":["An adjustment for interest rate risk embedded in counterparty agreements","The fair value adjustment to a derivative reflecting the risk of counterparty default \u2014 the market value of counterparty credit risk, reducing the value of derivatives assets by the present value of expected losses from potential counterparty failure","A regulatory capital charge for market risk in the trading book","The adjustment to bond prices for accrued interest between coupon dates"],"a":1,"e":"CVA = present value of expected losses from counterparty default. Post-2008, banks moved CVA from back-office accounting to front-office pricing \u2014 every OTC derivative now includes a CVA charge embedded in its price. DVA (Debit Valuation Adjustment) is the mirror: the value of your own potential default to the counterparty. Banks actively manage CVA via CDS hedging. Basel III introduced a separate CVA capital charge recognising these risks.","cat":"RATES","diff":"MD","mod":"Risk Management","concept":"CVA"},{"q":"What is a margin call and how does it create systemic risk?","o":["A regulatory demand for increased capital buffers during market stress","A demand for additional collateral when marked-to-market losses reduce collateral below a maintenance threshold \u2014 in stress, simultaneous margin calls across many leveraged investors force asset sales, depressing prices and triggering more margin calls in a self-reinforcing loop","A bank's demand for early loan repayment from a distressed borrower","A futures exchange's daily settlement of gains and losses between counterparties"],"a":1,"e":"Margin calls require posting additional collateral when positions move against you. The systemic risk: during market stress, margin calls hit many leveraged investors simultaneously. To raise cash, they sell assets \u2014 depressing prices \u2014 triggering margin calls for others. This procyclical mechanism amplified the 2008 GFC, the March 2020 COVID crash, and the 2022 UK LDI gilt crisis. Central clearing partially addresses this through standardised margining and default funds.","cat":"MACRO","diff":"VP","mod":"Risk Management","concept":"Margin call and systemic risk"},{"q":"What is duration mismatch and how did it cause Silicon Valley Bank's collapse?","o":["When a bank's loan maturities don't match its deposit maturities \u2014 an acceptable structural feature of all banking","SVB invested deposit proceeds into long-duration bonds during 2020-21 low rates. When the Fed hiked 525bp, these bonds lost ~20% of value. SVB held them at amortised cost avoiding recognition. When deposits shrank (tech startup outflows), SVB was forced to sell bonds at a loss, triggering panic and a classic bank run \u2014 a textbook duration mismatch in an extreme rate environment","When a bank's bond portfolio currency doesn't match its deposit currency","When a bank's floating-rate assets don't match its fixed-rate liabilities"],"a":1,"e":"SVB 2023: bought long-duration MBS and Treasuries (average duration ~6 years) with short-duration deposit liabilities. Fed hiking 525bp reduced MBS/Treasury values by ~$15-20% unrealised \u2014 held at amortised cost to avoid recognition. As tech startup clients withdrew deposits for cash needs, SVB was forced to crystallise losses, eroding its capital. The disclosed loss triggered panic withdrawals \u2014 $42bn in one day \u2014 and collapse. A classic ALM (asset-liability management) failure.","cat":"RATES","diff":"VP","mod":"Historical crises","concept":"SVB duration mismatch 2023"},{"q":"What is anchoring bias in financial decision-making?","o":["The tendency to follow the decisions of other investors \u2014 herding","The cognitive bias where individuals rely too heavily on the first piece of information encountered \u2014 investors anchor to purchase price, analysts to prior forecasts, leading to insufficient adjustment when new information arrives","The tendency to hold losing positions too long due to loss aversion","The bias of overweighting recent market events versus long-run history"],"a":1,"e":"Anchoring: once an anchor is set (entry price, analyst consensus, recent high), estimates stay too close to it even as new information arrives. Analysts update earnings forecasts insufficiently when companies miss expectations \u2014 anchored to prior estimates. Investors hold loss-making positions because they are anchored to their purchase price. In structured product pricing, anchoring to historical vol levels can cause mispricing when regimes shift.","cat":"EQUITY","diff":"VP","mod":"Behavioural Finance","concept":"Anchoring bias"},{"q":"What is the disposition effect?","o":["The tendency to concentrate investments in single stocks due to overconfidence","The empirically observed tendency to sell winners too early (to lock in gains) and hold losers too long (to avoid realising losses) \u2014 a consequence of loss aversion causing suboptimal portfolio turnover and tax management","The tendency for institutional investors to dispose of assets at year-end for tax purposes","The effect of positive market sentiment on asset returns"],"a":1,"e":"Disposition effect (Shefrin & Statman): investors treat gains and losses asymmetrically due to loss aversion. They sell winners prematurely to lock in the psychological satisfaction of a realised profit, while holding losers hoping to break even. This creates the momentum anomaly \u2014 recent winners continue outperforming because investors sell too soon; recent losers continue underperforming because investors hold too long.","cat":"EQUITY","diff":"VP","mod":"Behavioural Finance","concept":"Disposition effect"},{"q":"What is loss aversion in prospect theory?","o":["The rational preference for certainty over uncertainty in investment outcomes","Losses are psychologically roughly twice as painful as equivalent gains are pleasurable \u2014 causing investors to make suboptimal decisions to avoid realising losses, including holding losers too long and selling winners too early","The tendency for investors to lose money more often than they gain in volatile markets","The aversion to investments with high tracking error relative to a benchmark"],"a":1,"e":"Prospect theory (Kahneman & Tversky, 1979): the pain of a $100 loss is felt ~twice as intensely as the pleasure of a $100 gain. This asymmetry explains: why investors hold losers too long (avoiding loss realisation), why equity risk premiums are high (loss aversion demands extra compensation), and why certain structured products with capital protection sell well despite poor risk-adjusted returns \u2014 they eliminate the most painful outcome.","cat":"EQUITY","diff":"VP","mod":"Behavioural Finance","concept":"Loss aversion and prospect theory"},{"q":"What is herding behaviour in financial markets?","o":["Institutional investors copying index compositions to reduce tracking error","The tendency for investors to mimic the actions of a larger group rather than independently analysing information \u2014 creates momentum, bubbles, and crashes as mass behaviour amplifies price moves beyond fundamental value","The practice of following insider trading signals to generate alpha","The copying of successful hedge fund positions disclosed in 13F filings"],"a":1,"e":"Herding: rational or irrational tendency to follow the crowd. Rational herding occurs when investors infer information from others' actions. Career-risk herding: fund managers who differ from consensus and are wrong face job loss; those who are wrong with the crowd face less blame. Herding amplifies bubbles (1999-2000 tech, 2020-21 crypto) and crashes. It is a key source of systematic momentum and mean-reversion opportunities for contrarian investors.","cat":"EQUITY","diff":"VP","mod":"Behavioural Finance","concept":"Herding behaviour"},{"q":"What is the 'velocity of money' and what happened to it post-2008?","o":["The speed at which money moves between different asset classes","The number of times the average unit of currency is spent in a year (GDP/Money Supply). Post-2008, velocity collapsed as QE-created money was hoarded in bank reserves and savings rather than circulating through the economy \u2014 explaining why massive QE didn't immediately cause inflation","The rate at which foreign capital rotates between different economies","The speed of central bank reserve transfers between commercial banks"],"a":1,"e":"Velocity of money (V in MV=PT): declined sharply after 2008 as QE dramatically expanded M without proportional inflation or output growth \u2014 V fell. Banks held excess reserves rather than lending; households increased savings (deleveraging). This velocity trap explains why QE didn't immediately cause inflation. From 2021, fiscal stimulus pushed velocity back up as money flowed into spending \u2014 contributing to the inflation surge.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"Velocity of money"},{"q":"What is 'macroprudential policy' and how does it differ from monetary policy?","o":["Macro-level prudent investment policy for pension funds","Regulatory tools targeting systemic financial stability risks (credit booms, asset bubbles, bank leverage) rather than price stability \u2014 examples include countercyclical capital buffers, LTV limits for mortgages, and leverage limits for banks. Complements monetary policy which is too blunt for targeted asset market risks","Government policy ensuring macro-level prudent fiscal management","IMF framework for providing macroprudential advice to member countries"],"a":1,"e":"Macroprudential policy addresses market failures causing systemic risk: excessive credit growth, asset bubbles, interconnectedness. Key tools: countercyclical capital buffers (banks hold more capital in booms, release in busts), sectoral capital requirements (extra capital for housing loans), LTV and DSTI limits for household borrowing. Unlike interest rates (affecting the whole economy), macroprudential tools target specific sector risks \u2014 cooling a housing boom without harming business investment.","cat":"MACRO","diff":"MD","mod":"Monetary policy","concept":"Macroprudential policy"},{"q":"What is 'Goodhart's Law' and why is it important for policymakers?","o":["Higher interest rates always produce lower inflation \u2014 named after Charles Goodhart","'When a measure becomes a target, it ceases to be a good measure.' When a statistical regularity is used as a policy target, agents change behaviour in response, destroying the measure's reliability as an indicator","Economic growth always accelerates after three consecutive positive GDP quarters","Monetary base always predicts nominal GDP with a six-month lag"],"a":1,"e":"Goodhart's Law (Charles Goodhart, 1975): targeting a measure corrupts it as agents optimise against the policy. Historical examples: targeting M3 money supply (1980s UK) caused financial innovation to circumvent the measure; targeting bank capital ratios led to off-balance-sheet vehicles; targeting unemployment rate led to participation rate gaming. The Lucas Critique is the rational-expectations version of this same insight.","cat":"MACRO","diff":"MD","mod":"Economic thought","concept":"Goodhart's Law"},{"q":"What is 'hysteresis' in economics?","o":["The tendency for inflation to persist above target during economic recoveries","The persistence of economic effects after the original cause has been removed \u2014 temporary recessions can cause permanent damage to productive capacity and skills, reducing long-run potential GDP and meaning the natural unemployment rate itself responds to history","The tendency for exchange rates to overshoot long-run equilibrium and slowly revert","The persistence of current account imbalances despite exchange rate adjustments"],"a":1,"e":"Hysteresis in labour markets: unemployed workers lose skills, connections, and labour force attachment \u2014 temporary cyclical unemployment can become structural. Key implications: (1) allowing deep recessions may permanently reduce potential GDP; (2) the natural rate of unemployment may itself be path-dependent. This is a key argument for aggressive countercyclical policy \u2014 preventing deep recessions protects long-run supply capacity, not just short-run demand.","cat":"MACRO","diff":"MD","mod":"Economic thought","concept":"Hysteresis in economics"},{"q":"What is the Mundell-Fleming model and what does it predict about fiscal policy?","o":["A model predicting that fiscal and monetary policy always reinforce each other","Under floating exchange rates, fiscal expansion raises rates, attracting capital, appreciating the currency, crowding out net exports \u2014 leaving output unchanged. Under fixed rates, the central bank accommodates fiscal expansion, making fiscal policy highly effective","A model showing monetary policy is always more effective than fiscal policy","A model predicting small open economies cannot use either policy effectively"],"a":1,"e":"Mundell-Fleming (open economy IS-LM): under floating rates, fiscal expansion \u2192 higher rates \u2192 capital inflow \u2192 currency appreciation \u2192 crowding out of net exports \u2192 output unchanged (fiscal policy ineffective). Under fixed rates \u2192 central bank buys foreign exchange \u2192 money supply expands \u2192 full fiscal multiplier applies. This explains why fiscal multipliers are generally lower in small open economies with floating currencies.","cat":"MACRO","diff":"MD","mod":"Monetary policy","concept":"Mundell-Fleming model"},{"q":"What is the neo-Fisherian paradox in monetary policy?","o":["Higher nominal rates always cause inflation by stimulating demand","The counterintuitive proposition that persistently low rates may cause low inflation (not cure it) because the Fisher effect means low nominal rates eventually anchor low inflation expectations \u2014 Japan's decades of near-zero rates and near-zero inflation is the key empirical case","Central banks should target nominal GDP rather than inflation","Fiscal policy rather than monetary policy determines inflation in the long run"],"a":1,"e":"Neo-Fisherism: if nominal rate = real rate + inflation (Fisher), then permanently low nominal rates might eventually anchor inflation expectations permanently low. Japan's experience \u2014 decades near-zero rates yet near-zero or negative inflation \u2014 provides the main empirical motivation. This challenges the conventional view that lower rates always stimulate inflation. It remains controversial but has influenced debates about the persistence of low-inflation regimes.","cat":"MACRO","diff":"MD","mod":"Inflation","concept":"Neo-Fisherian paradox"},{"q":"What is the FX 'carry-to-vol' ratio?","o":["The ratio of a currency pair's carry to its spot price","The interest rate differential divided by the implied volatility of a currency pair \u2014 measures risk-adjusted carry attractiveness. High carry-to-vol means good compensation for volatility risk; used to rank carry trades and size positions systematically","The ratio of overnight funding costs to the 3-month forward premium","The relationship between central bank carry policies and market volatility regimes"],"a":1,"e":"Carry-to-vol: interest rate differential / implied vol. A pair offering 500bp carry with 5% vol gives carry-to-vol of 1.0; same carry with 10% vol gives 0.5. Systematic carry strategies rank pairs by carry-to-vol and go long the top quartile, short the bottom \u2014 a risk-adjusted approach to currency carry. It disciplines position sizing: don't take as much carry risk in high-volatility currencies regardless of the absolute rate differential.","cat":"FX","diff":"MD","mod":"FX carry","concept":"Carry-to-vol ratio"},{"q":"What is petrodollar recycling and how does it affect global bond markets?","o":["The process by which oil companies convert revenues into domestic currency","The flow of dollar oil export revenues from OPEC nations back into US Treasury bonds and other dollar assets \u2014 oil exporters accumulate dollar reserves and recycle them into US securities, suppressing Treasury yields and funding US current account deficits","The conversion of petrodollars into gold by oil-exporting nations","The mechanism by which oil prices affect the US Dollar Index"],"a":1,"e":"Petrodollar recycling: oil exporters (Saudi Arabia, Gulf states) receive USD for oil and invest surpluses in US Treasuries, agency bonds, and equities. This creates structural demand for dollar assets, suppressing US yields and enabling US current account deficits to be financed at low rates. When oil prices collapse (2014-16), recycling slows \u2014 Gulf nations sold reserves, reducing structural Treasury demand and pushing yields higher.","cat":"FX","diff":"VP","mod":"FX mechanics","concept":"Petrodollar recycling"},{"q":"What is triangular arbitrage?","o":["Simultaneous trading of three FX pairs to profit from pricing inconsistencies \u2014 if EUR/USD, USD/JPY, and EUR/JPY are not mutually consistent, a risk-free profit can be extracted by trading all three","Converting currency through three intermediate currencies to minimise transaction costs","A three-way hedging strategy combining FX forwards, options, and swaps","The arbitrage between onshore and offshore markets for the same currency"],"a":0,"e":"Triangular arbitrage: if EUR/USD = 1.10, USD/JPY = 150, but EUR/JPY \u2260 165, a riskless profit can be locked by simultaneously trading all three pairs. Electronic trading has made such opportunities extremely rare and short-lived \u2014 prices adjust within milliseconds as algorithms detect and trade away the discrepancy. The near-zero occurrence of triangular arbitrage opportunities is strong evidence of FX market efficiency for major currency pairs.","cat":"FX","diff":"VP","mod":"FX mechanics","concept":"Triangular arbitrage"},{"q":"What is the FX 'fixing scandal' and what did it involve?","o":["A 2012-15 scandal where traders at major banks coordinated via chat rooms to position ahead of clients' WM/Reuters 4pm fixing orders, moving the rate against client interests to generate risk-free profits at client expense","A central bank scandal involving manipulation of official intervention reference rates","A scandal involving incorrect automated FX settlement calculations across major exchanges","A scandal involving false reporting of FX options positions to regulators"],"a":0,"e":"FX fixing scandal (2012-15): traders shared information about large client fix orders via chat rooms ('The Cartel', 'The Bandits Club'). Knowing a client needed to buy EUR at the fix, traders would buy EUR ahead of the fix window, push the rate up, fill the client at a worse price, then unwind. Banks including Barclays, UBS, Citi, JPMorgan, RBS paid $10bn+ in fines. Led to reforms in WM/Reuters fixing methodology and conduct regulations.","cat":"FX","diff":"VP","mod":"FX mechanics","concept":"FX fixing scandal"},{"q":"What is the Plaza Accord of 1985?","o":["A 1985 OPEC agreement to cut oil production to stabilise prices","A G5 agreement (US, UK, France, Germany, Japan) to intervene collectively in currency markets to depreciate the US dollar \u2014 addressing the massive US current account deficit. The dollar fell ~50% against JPY and DEM over the next two years \u2014 the most successful coordinated FX intervention in history","A 1985 trade agreement between the US and Japan reducing Japanese car import quotas","A 1985 agreement between the Fed and Treasury to coordinate monetary and fiscal policy"],"a":1,"e":"Plaza Accord (September 1985): the dollar had strengthened ~50% since 1980 due to Reagan fiscal deficits and Volcker high rates, devastating US manufacturing competitiveness. G5 finance ministers agreed to joint market intervention to weaken the dollar. USD/JPY fell from 240 to 120 by 1987. The resulting yen appreciation was so severe it contributed to Japan's subsequent ultra-loose monetary policy and the late-1980s asset price bubble.","cat":"FX","diff":"VP","mod":"Historical crises","concept":"Plaza Accord 1985"},{"q":"What is equity duration?","o":["The average time to receive equity dividends, weighted by present value","The sensitivity of equity prices to changes in interest rates \u2014 growth stocks with earnings far in the future have high equity duration and are most hurt by rising discount rates; value stocks with near-term earnings have lower equity duration","The time until a company achieves positive earnings","The maturity of corporate bonds issued by a company"],"a":1,"e":"Equity duration: like bond duration, measures how sensitive equity valuations are to discount rate changes. High-growth companies (tech, biotech) have most of their value in distant future cash flows \u2014 like long-duration bonds, their prices fall sharply when rates rise. The 2022 tech selloff was a direct mathematical consequence of rising real yields (from -1% to +2%) hitting high-equity-duration assets, compressing their valuations dramatically.","cat":"EQUITY","diff":"VP","mod":"Equity valuation","concept":"Equity duration"},{"q":"What is factor investing and what are the main equity factors?","o":["Investing based on macroeconomic factors like GDP growth and inflation","A systematic approach to investing based on characteristics that have historically generated excess returns: value (cheap stocks), momentum (recent winners), quality (high profitability), low volatility (less volatile stocks), and size (small caps) \u2014 each representing a distinct risk premium","Investing exclusively in factor analysis rather than fundamental company analysis","A strategy of buying all factors equally weighted across all markets"],"a":1,"e":"Factor investing (Fama-French, Carhart): long-documented return premiums for Value (P/B, P/E), Momentum (12M-1M return), Quality (ROE, low leverage), Low-Vol (beta, volatility), and Size (market cap). Risk-based explanations: value compensates for distress risk, momentum for underreaction, quality for defensive characteristics. Factor premiums are cyclical \u2014 momentum works well in trending markets; value in recoveries from distress.","cat":"EQUITY","diff":"VP","mod":"Equity valuation","concept":"Factor investing"},{"q":"What is short selling and what unique risks does it carry?","o":["Selling bonds before the coupon payment date","Borrowing shares and selling them, profiting if the price falls \u2014 unique risks: theoretically unlimited losses (price can rise infinitely), short squeeze (coordinated buying forces shorts to cover at rising prices), stock borrow cost, and dividend obligation to the lender","Selling futures contracts on an equity index to hedge a portfolio","Selling covered call options on a stock position to generate income"],"a":1,"e":"Short selling: borrow shares, sell at current price, repurchase cheaper to profit. Key risks: (1) unlimited theoretical loss \u2014 price can rise indefinitely while profits are capped at the short price; (2) short squeeze \u2014 coordinated buying (GameStop 2021 is the defining modern example) forces margin calls causing explosive covering rallies; (3) borrow costs that erode returns over time; (4) timing risk \u2014 correct thesis can take years before the price falls.","cat":"EQUITY","diff":"VP","mod":"Equity valuation","concept":"Short selling risks"},{"q":"What is the difference between systematic and idiosyncratic risk?","o":["Systematic risk affects all assets in the same direction; idiosyncratic risk is specific to individual assets \u2014 only systematic risk earns a risk premium in well-diversified portfolios","Systematic risk is predictable; idiosyncratic risk is random","Systematic risk applies to equities; idiosyncratic risk applies to bonds only","Systematic risk is regulated; idiosyncratic risk is unregulated"],"a":0,"e":"Systematic risk (market beta): market-wide risk that cannot be diversified away \u2014 compensated by the equity risk premium. Idiosyncratic risk (company-specific): diversifies away in a large portfolio \u2014 receives no premium because rational investors can eliminate it for free. CAPM: only systematic risk earns a return premium. Active managers aim to generate alpha (positive idiosyncratic return) while managing their systematic market exposure (beta).","cat":"EQUITY","diff":"VP","mod":"Equity valuation","concept":"Systematic vs idiosyncratic risk"},{"q":"What is the energy transition and its commodity implications?","o":["The shift from coal to natural gas, requiring more gas infrastructure","The global shift from fossil fuels to renewables (solar, wind, EVs) \u2014 creating structural demand for copper (electrical infrastructure), lithium (batteries), cobalt/nickel (EV batteries), and rare earths (wind turbines), while potentially reducing long-run oil demand","A government programme replacing ageing energy infrastructure without changing fuel sources","The commodity market adjustment from winter to summer energy demand cycles"],"a":1,"e":"Energy transition commodities: solar, wind, and EVs require significantly more copper, lithium, nickel, cobalt, and manganese per unit of energy than fossil fuel systems. IEA estimates achieving net zero by 2050 requires 4x current copper production. This structural demand shift, combined with mining investment cycle lags (mines take 5-10 years to develop), underpins the commodity super-cycle thesis for base metals and battery materials.","cat":"COMMODITIES","diff":"VP","mod":"Commodity cycles","concept":"Energy transition commodity demand"},{"q":"What is the convenience yield in commodity markets?","o":["The premium paid for commodities conveniently available in electronic markets","The implied benefit of physically holding a commodity rather than a futures contract \u2014 when physical supply is tight, holders of physical inventory benefit from having immediate access, reflected in backwardation (spot above futures)","The yield earned from investing commodity export revenues in government bonds","The interest rate applied to commodity-backed lending"],"a":1,"e":"Convenience yield: the non-monetary benefit of holding physical commodity inventory \u2014 the ability to keep production running, meet unexpected demand, or profit from spot shortages. When supply is tight, convenience yield is high, pushing spot prices above futures (backwardation). When supply is ample, storage costs dominate (contango). The convenience yield shape of the futures curve conveys real-time information about physical market tightness.","cat":"COMMODITIES","diff":"MD","mod":"Futures mechanics","concept":"Convenience yield"},{"q":"What is oil price 'pass-through' to inflation?","o":["Oil price changes pass through to headline CPI instantly and completely","Oil price changes affect consumer prices through direct energy costs (typically 5-10% of CPI basket) and indirect effects (transport, manufacturing). Pass-through varies by: energy intensity of the economy, government subsidies, currency moves, and whether central banks 'look through' temporary energy shocks","Oil price changes never affect core CPI, only headline inflation","Oil pass-through is identical in all countries regardless of energy mix"],"a":1,"e":"Oil pass-through: a 10% oil price rise typically adds 0.2-0.5pp to headline CPI directly, more via indirect effects on transport and manufacturing. Pass-through is higher in energy-intensive economies and those without fuel subsidies. Central banks typically 'look through' first-round energy price effects but worry when second-round effects (wage demands, service price increases) emerge \u2014 the 2022 European energy shock tested this distinction severely.","cat":"COMMODITIES","diff":"VP","mod":"Oil","concept":"Oil price pass-through to CPI"},{"q":"What is 'carry' in interest rate markets?","o":["The interest income earned on a bond minus the cost of financing it \u2014 also called the 'cost of carry', representing the net return from simply holding a position if the yield curve doesn't change","The premium earned from providing market-making liquidity in bond markets","The profit from buying cheap bonds and selling expensive ones","The excess return from active duration management"],"a":0,"e":"Carry in rates: the return earned if nothing changes. For a bond yielding 4.5% financed at 5.25% overnight, carry is -0.75% (negative \u2014 you pay to hold it). For a 2Y bond yielding 5.1% financed at 5.25%, carry is -0.15%. Carry determines the cost of holding positions over time. The 'carry-roll-down' combines carry with the expected price appreciation as a bond rolls down a positively-sloped yield curve \u2014 a core concept in fixed income relative value.","cat":"RATES","diff":"MD","mod":"Rates Mechanics","concept":"Carry in interest rate markets"},{"q":"What is 'roll-down' return in bond investing?","o":["The capital loss when bond prices fall as yields rise","On an upward-sloping yield curve, as time passes a bond rolls down the curve \u2014 a 10Y bond becomes a 9Y bond one year later; if the curve is unchanged, it prices at the lower 9Y yield, generating capital appreciation to supplement the coupon","The process of rolling over maturing short-term bonds into new issues","The reduction in bond duration as a bond approaches maturity"],"a":1,"e":"Roll-down (roll return): on a positively-sloped curve, time's passage causes a bond to 'roll' to a lower yield \u2014 a 10Y bond yielding 4.5% becomes a 9Y bond yielding 4.2% one year later (if the curve is unchanged), generating ~1.5% capital gain (price appreciation). Combined with carry (coupon minus funding cost), the carry-roll-down is a key total return driver in fixed income and a core input in bond relative value analysis.","cat":"RATES","diff":"VP","mod":"Rates Mechanics","concept":"Roll-down return"},{"q":"What is the cash-bond to futures basis?","o":["The credit spread between corporate and government bonds","The price difference between a cash bond and the equivalent futures contract, reflecting financing costs (repo rate), accrued interest, and the cheapest-to-deliver option in futures \u2014 basis can be positive or negative and is actively traded by basis traders","The yield spread between on-the-run and off-the-run Treasury bonds","The difference between a bond's ask and bid price"],"a":1,"e":"Bond basis = cash bond price minus futures price (adjusted for conversion factor). Components: (1) net carry (coupon minus repo); (2) the delivery option (futures sellers choose which bond to deliver \u2014 cheapest-to-deliver option has positive value). Basis trading exploits pricing between cash and futures. During stress (2008, March 2020), basis blew out as funding markets froze and forced selling disconnected cash from futures \u2014 creating large, high-risk opportunities.","cat":"RATES","diff":"MD","mod":"Rates Mechanics","concept":"Cash-futures basis"},{"q":"What is the swap spread and what does it signal?","o":["The swap rate is always lower than Treasury yields due to lower credit risk","The fixed rate on an interest rate swap minus the equivalent-maturity Treasury yield \u2014 reflects bank credit risk, supply/demand for fixed-rate paying (pension funds, mortgage hedgers), and dealer balance sheet costs. Can be positive or negative","The rate charged by clearing houses on margined derivatives positions","The difference between the 2Y and 10Y swap rates \u2014 a yield curve measure"],"a":1,"e":"Swap spread = IRS fixed rate minus Treasury yield. Historically positive (bank credit risk premium over risk-free). Post-2008 and post-COVID, US 30Y swap spreads turned negative \u2014 unusual, reflecting: (1) regulatory constraints reducing dealer balance sheet capacity for arbitrage; (2) heavy Treasury supply pushing yields up relative to swaps; (3) structural demand from pension funds and insurance companies to receive fixed in swaps (pushing swap rates down).","cat":"RATES","diff":"MD","mod":"Rates Mechanics","concept":"Swap spreads"},{"q":"What is the Volcker Rule and what market impact did it have?","o":["The historical rule Paul Volcker used to fight inflation, codified as law requiring 20% rates in crisis","Post-2008 Dodd-Frank provision prohibiting banks from proprietary trading and limiting their stakes in hedge funds and PE funds \u2014 reduced market-making capacity and contributed to reduced bond market liquidity, particularly in corporate bonds","A rule requiring banks to hold a minimum volume of US Treasury bonds","Paul Volcker's recommendation that central banks use fixed money supply growth rules"],"a":1,"e":"Volcker Rule (implemented 2014): prohibited federally insured banks from proprietary trading and restricted PE/HF investments. Market impact: dealer banks dramatically reduced bond inventories and market-making activity. Corporate bond market liquidity deteriorated \u2014 bid-ask spreads widened and large block trades became harder to execute without market impact. The trade-off: reduced systemic risk from speculative bank trading versus reduced market liquidity in stress periods.","cat":"MACRO","diff":"VP","mod":"Historical crises","concept":"Volcker Rule market impact"},{"q":"What is the 'reflation trade' and when does it outperform?","o":["A strategy of buying inflation-linked bonds exclusively during reflationary periods","The trade that positions for accelerating growth and rising inflation: long commodities, energy, materials, value stocks, financials, short-duration bonds, long breakeven inflation \u2014 typically outperforms during early recovery phases when growth accelerates from a low base while monetary policy remains accommodative","A strategy of buying gold exclusively during reflationary periods","The trade of buying emerging market equities as a pure play on global reflation"],"a":1,"e":"Reflation trade: growth accelerating from below-trend toward above-trend, with rising inflation but still-easy monetary policy. Key positions: long commodities (rising demand), energy stocks (oil price leverage), financials (steeper yield curve improves net interest margin), value/cyclical equities, short long-duration bonds, long breakeven inflation. The 2020-21 post-COVID recovery was a classic reflation environment \u2014 until inflation became persistent and central banks were forced to tighten aggressively.","cat":"MACRO","diff":"VP","mod":"Cross-asset","concept":"Reflation trade"},{"q":"What is the efficient frontier in modern portfolio theory?","o":["The set of portfolios with maximum possible return regardless of risk","The set of portfolios offering maximum expected return for each level of risk \u2014 portfolios on the frontier cannot be improved (higher return without more risk, or lower risk without less return). The key insight: combining assets with low correlations achieves better risk-return trade-offs than holding any single asset","The set of portfolios that perfectly track a benchmark index","The set of portfolios held by the most successful institutional investors"],"a":1,"e":"Efficient frontier (Markowitz, 1952): diversification allows investors to reduce risk without proportionally reducing return. The frontier identifies all 'efficient' portfolios \u2014 none dominated by another with higher return and lower risk. This quantified the benefit of diversification and launched modern portfolio theory. The optimal portfolio on the frontier depends on investor risk preferences and the Capital Market Line (adding the risk-free asset).","cat":"MACRO","diff":"VP","mod":"Cross-asset","concept":"Efficient frontier"},{"q":"What is the Sharpe ratio and its key limitations?","o":["Return divided by maximum drawdown \u2014 a comprehensive risk-adjusted measure","Excess return over the risk-free rate divided by volatility \u2014 measures return per unit of total risk. Limitations: assumes normal distributions (understates tail risk), uses standard deviation which penalises upside equally with downside, and can be gamed by smoothing returns or using leveraged strategies with fat left tails","Return divided by maximum portfolio leverage","The ratio of alpha to beta \u2014 measuring skill versus market exposure"],"a":1,"e":"Sharpe = (Return - Rf) / Volatility. Widely used but limited: (1) symmetric risk measure \u2014 doesn't distinguish downside from upside volatility; (2) fails for non-normal distributions \u2014 strategies selling tail risk (short vol, short puts) show artificially high Sharpe until they blow up; (3) can be maximised by smoothing return reporting (hedge funds using illiquid assets); (4) ignores liquidity risk. Sortino (downside deviation) and Calmar (return/max drawdown) address some limitations.","cat":"MACRO","diff":"VP","mod":"Cross-asset","concept":"Sharpe ratio limitations"},{"q":"What is the Kelly criterion for position sizing?","o":["A regulatory guideline for maximum position size in derivatives","A mathematical formula for the optimal fraction of capital to risk on a trade to maximise long-run wealth growth: f = (bp - q) / b, where p = win probability, q = loss probability, b = win/loss ratio. Full Kelly is often too aggressive; practitioners use 'half Kelly' to reduce volatility of the growth path","A risk management rule requiring positions be reduced when losses exceed a threshold","The criterion used by rating agencies to assess leverage in structured finance"],"a":1,"e":"Kelly criterion (J.L. Kelly, 1956): maximises expected logarithmic wealth (geometric growth rate). Example: 60% win rate, 1:1 payoff \u2192 Kelly says bet 20% of capital. Practical issues: requires precise probability estimates (rarely available in markets), produces high portfolio volatility, and assumes no correlation between bets. Half-Kelly (bet 10% in the example) significantly reduces variance at modest cost to long-run growth. Widely used in quant funds and by sophisticated investors.","cat":"MACRO","diff":"MD","mod":"Cross-asset","concept":"Kelly criterion"},{"q":"What is maximum drawdown and why do institutional investors focus on it?","o":["The maximum single-day loss ever experienced by a portfolio","The maximum peak-to-trough decline over any period \u2014 determines investor redemption behaviour and manager career risk. A 50% drawdown requires 100% return to recover. Institutional investors scrutinise it because large drawdowns trigger client redemptions, force selling at bottoms, and lead to manager termination","The maximum loss allowed under risk management guidelines","The maximum annual loss acceptable within an investment mandate"],"a":1,"e":"Maximum drawdown: if a portfolio peaks at 100, falls to 60, recovers to 110, falls to 55 \u2014 max drawdown is 45% (100 to 55). Recovery mathematics: a 33% loss needs 50% gain to recover; a 50% loss needs 100%. Institutional investors focus on drawdown because: (1) clients redeem after large drawdowns, causing forced selling at bottoms; (2) managers are fired; (3) recovering from large drawdowns may take a decade or more \u2014 potentially destroying the fund's track record permanently.","cat":"MACRO","diff":"VP","mod":"Cross-asset","concept":"Maximum drawdown"},{"q":"What was the Argentine peso crisis of 2001-2002?","o":["A brief devaluation quickly stabilised by IMF intervention","Argentina's 1:1 USD peg via currency board (since 1991) became unsustainable as the dollar appreciated, fiscal deficits grew, and the economy contracted. In January 2002, the peg collapsed, the peso devalued 75%, and Argentina defaulted on $100bn of sovereign debt \u2014 at the time the largest sovereign default in history","A currency crisis caused by speculative attacks despite sound fundamentals","A managed devaluation successfully restoring Argentine competitiveness"],"a":1,"e":"Argentina 2001: the currency board (1 peso = 1 USD since 1991) initially ended hyperinflation but required internal flexibility (wage/price cuts) for adjustment without devaluation. As competitiveness eroded and deficits grew, capital fled. The corralito (deposit freeze) triggered social unrest and a cascade of presidential resignations. The eventual default and pesification (converting USD contracts to pesos) wiped out foreign investors' savings. The defining case study of currency board fragility.","cat":"FX","diff":"VP","mod":"Historical crises","concept":"Argentina 2001 crisis"},{"q":"What was Black Wednesday (1992) and what did it demonstrate?","o":["The 1992 US stock market crash following the first Gulf War","When the UK was forced to withdraw from the European Exchange Rate Mechanism (ERM) after George Soros and others sold GBP so aggressively that the Bank of England could not maintain the DEM 2.95 floor despite raising rates to 15% \u2014 demonstrating that a determined speculative attack can break a fixed peg if fundamentals don't support it","A 1992 collapse of Japanese banks following the asset bubble bursting","The 1992 US Federal Reserve emergency rate cut causing a bond market crash"],"a":1,"e":"Black Wednesday (September 16, 1992): the UK had entered the ERM at an overvalued rate (DEM 2.95), with high inflation and weak growth. Soros's Quantum Fund and others identified the fundamental misalignment and short-sold GBP aggressively. The BOE raised rates to 15% (intraday) and spent \u00a33.3bn of reserves defending the peg before abandoning it. Soros made ~$1bn profit. The lesson: fixed exchange rates without fundamental support cannot withstand determined speculative attack.","cat":"FX","diff":"VP","mod":"Historical crises","concept":"Black Wednesday 1992"},{"q":"What was the 2010 'Flash Crash' and what caused it?","o":["A government-triggered stock market halt during the Eurozone crisis","On May 6, 2010 the Dow Jones fell nearly 1,000 points (9%) intraday in minutes before recovering almost entirely \u2014 caused by a large algorithmic futures sell order interacting with high-frequency traders stepping back from markets, creating feedback loops that momentarily sent major stock prices to extreme levels","A high-frequency trading scandal causing a brief technology stock dislocation","A Fed communication error causing a sudden equity selloff and immediate recovery"],"a":1,"e":"Flash Crash (May 6, 2010): a large futures sell order from Waddell & Reed triggered market instability. High-frequency traders withdrew liquidity as volatility rose, removing stabilising market-making. Feedback loops developed: falling prices triggered more selling, driving prices to absurd extremes (some stocks briefly hit $0.01 or $100,000). Recovery was almost instant. The event led to circuit breaker reforms, increased scrutiny of HFT, and highlighted fragility in automated market structures.","cat":"EQUITY","diff":"VP","mod":"Historical crises","concept":"Flash Crash 2010"},{"q":"What was the 'Tequila Crisis' of 1994-1995?","o":["A financial crisis caused by the collapse of Mexican tequila exports","Mexico's peso devaluation in December 1994 triggered a severe financial crisis \u2014 large current account deficit financed by short-term dollar-linked bonds (Tesobonos) became unsustainable when capital fled. The peso fell 50%, Mexico needed a $50bn US Treasury rescue package. Contagion spread to other EM currencies \u2014 the 'Tequila effect'","A banking crisis caused by excessive Mexican bank lending to the agricultural sector","A US financial crisis caused by the failure of derivatives positions linked to Mexican interest rates"],"a":1,"e":"Mexico 1994-95 (Tequila Crisis): Mexico ran a large current account deficit financed by foreign capital attracted by high rates and the peso-dollar peg. As US rates rose (Fed hiking 1994), capital fled. Mexico had rolled short-term debt into Tesobonos (dollar-linked peso bonds) \u2014 when the peso fell 50%, these became extremely expensive. The US Treasury and IMF provided $50bn in emergency support. Led to the 'IMF bailout' debate and influenced Asia's reserve-building post-1997.","cat":"FX","diff":"VP","mod":"Historical crises","concept":"Mexico Tequila Crisis 1994"},{"q":"What are the 'five Cs of credit'?","o":["Currency, Collateral, Cycle, Covenant, Counterparty","Character (willingness to repay), Capacity (cash flow ability), Capital (equity cushion), Collateral (asset backing), Conditions (economic environment) \u2014 the classic framework for assessing credit risk in lending and bond analysis","Cost, Complexity, Covenant, Counterparty, Currency","Credit score, Collateral, Cash flow, Cycle, Counterparty"],"a":1,"e":"The 5 Cs provide a holistic credit assessment framework. Character: management integrity and track record. Capacity: debt service coverage from operating cash flows. Capital: equity cushion (first-loss buffer for lenders). Collateral: asset quality and recoverability in default. Conditions: industry cyclicality, competitive position, macro environment. Modern credit analysis builds on this framework with quantitative metrics (leverage ratios, interest coverage, free cash flow conversion).","cat":"RATES","diff":"ANALYST","mod":"Credit","concept":"Five Cs of credit"},{"q":"What is Net Debt/EBITDA and what level indicates distress?","o":["Total liabilities divided by total assets \u2014 the balance sheet leverage measure","Net debt (gross debt minus cash) divided by EBITDA (operating earnings) \u2014 measures how many years of operating earnings are needed to repay net debt. Investment grade typically below 2-3x; high yield 4-6x; above 6-7x indicates highly leveraged/distressed territory, especially in a rising rate environment","Gross debt divided by revenue \u2014 how much debt per dollar of sales","Total liabilities divided by total equity \u2014 the traditional leverage ratio"],"a":1,"e":"Net Debt/EBITDA: the most widely used corporate leverage metric. Rating agency targets: AAA companies often below 1x; investment grade 2-3x; high yield 4-6x; distressed above 6x. Context matters: utilities can sustain 5-6x due to stable regulated cash flows; cyclicals should stay below 3x to survive downturns. Rising rates compound leverage risk: at 6x leverage with floating-rate debt, a 2% rate rise adds ~0.5x to the 'effective leverage' burden.","cat":"RATES","diff":"VP","mod":"Credit","concept":"Corporate leverage analysis"},{"q":"What is a covenant in bond or loan documentation?","o":["A legal agreement between two governments on debt repayment terms","A contractual obligation restricting borrower behaviour (negative covenants) or requiring specific actions (positive covenants) \u2014 examples: maximum leverage ratio, minimum interest coverage, restrictions on asset sales, dividends, or additional debt. Violations trigger default provisions giving lenders remedies","The currency denomination clause in international bond documentation","The credit rating minimum required for a bond to remain in investment grade indices"],"a":1,"e":"Covenants protect lenders by limiting borrower risk-taking post-loan. Maintenance covenants (bank loans): tested quarterly \u2014 if leverage exceeds 4x, lenders can demand repayment or restructure terms. Incurrence covenants (bonds): only tested when the borrower takes specific actions (issues more debt, pays dividends). The 2010s saw 'covenant-lite' loans proliferate, weakening lender protections \u2014 a risk that crystallised in 2022-23 as rates rose and operating performance deteriorated.","cat":"RATES","diff":"VP","mod":"Credit","concept":"Covenants in bonds and loans"},{"q":"What are the main channels through which QE works?","o":["QE works identically to traditional open market operations","QE transmission: (1) portfolio balance \u2014 pushing investors from bonds into riskier assets; (2) signalling \u2014 committing to low rates for longer; (3) exchange rate \u2014 currency weakens via lower rates; (4) wealth effect \u2014 higher asset prices stimulate spending. None of these channels is guaranteed, and effectiveness varied across episodes","QE works solely by reducing bank funding costs to increase business lending","QE works by directly injecting cash into household bank accounts"],"a":1,"e":"QE channels: portfolio rebalancing (investors forced from bonds into equities/credit), duration extraction (reducing supply of long-term bonds, pushing yields down), signalling (commitment to low rates for longer), currency depreciation (lower rates reduce currency attractiveness), and wealth effect (higher asset prices stimulate spending). QE successfully prevented deflation post-2008 and post-COVID. Diminishing returns set in at very large scale, and the 'reversal rate' debate questions whether ultra-low rates may reduce bank lending by compressing margins.","cat":"MACRO","diff":"VP","mod":"Monetary policy","concept":"QE transmission channels"},{"q":"What is 'outcome-based forward guidance'?","o":["Forward guidance that applies only to interest rate outcomes, not asset purchase programmes","Forward guidance that ties policy commitments to specific economic conditions being met (e.g. 'low rates until unemployment falls below 6.5% AND inflation is sustained above 2%') rather than a calendar date \u2014 more credible because it automatically adjusts to the economic situation","Forward guidance used only by developing country central banks","Forward guidance that specifies the exact path of future rate changes"],"a":1,"e":"Outcome-based guidance: the Fed evolved from vague ('extended period'), to calendar-based ('at least through mid-2015'), to outcome-based ('until unemployment below 6.5%'). Outcome-based is theoretically superior \u2014 it adjusts automatically to economic conditions and aligns policy with the central bank's actual goals. The limitation: it requires the public to forecast the economy's path, making communication more complex than a simple date.","cat":"MACRO","diff":"MD","mod":"Central banks","concept":"Outcome-based forward guidance"},{"q":"What is the 'reversal rate' concept in monetary policy?","o":["The interest rate at which monetary easing reverses a country's current account deficit","The interest rate below which further cuts may become contractionary \u2014 ultra-low rates can reduce bank profitability (compressing net interest margins), causing banks to lend less rather than more. If banks are sufficiently impaired, the stimulus from lower rates is offset by reduced credit supply","The rate at which the central bank reverses its QE asset purchases","The exchange rate level at which the central bank reverses its intervention stance"],"a":1,"e":"Reversal rate (Brunnermeier & Koby): cuts below a threshold may reduce credit supply by impairing bank profitability \u2014 negative rates in particular squeeze net interest margins if banks cannot pass negative rates to retail depositors. Evidence: European and Japanese banks showed lending slowdowns during negative rate periods. This limits how low rates can go usefully and helps explain why negative rates had smaller-than-expected economic effects in the Eurozone and Japan.","cat":"MACRO","diff":"MD","mod":"Monetary policy","concept":"Reversal rate"},{"q":"What is the Keynesian vs Monetarist debate on business cycle policy?","o":["Keynesians believe markets self-correct; monetarists believe government intervention is necessary","Keynesian view: markets fail to self-correct quickly \u2014 sticky wages/prices mean recessions persist without intervention, requiring active fiscal and monetary stimulus. Monetarist view (Friedman): markets self-correct efficiently; monetary instability causes cycles \u2014 policy should follow rules rather than discretion to avoid lags and errors","Both agree on fiscal policy; they only disagree on monetary policy","Keynesians focus only on short run; monetarists only on long run"],"a":1,"e":"The Keynesian-Monetarist debate shaped 20th-century macro policy. Keynes (1936): sticky prices and pessimistic expectations can trap economies in low equilibrium \u2014 government spending fills demand gaps. Friedman/Schwartz: Great Depression was caused by monetary contraction, not market failure. Friedman's policy rule: fixed money growth avoids discretionary policy mistakes and long lags. The 1970s stagflation \u2014 which Keynesian models failed to anticipate \u2014 shifted opinion toward monetarism and eventually New Keynesian synthesis.","cat":"MACRO","diff":"VP","mod":"Economic thought","concept":"Keynesian vs Monetarist debate"},{"q":"What is rational expectations theory and how did it change macroeconomics?","o":["The theory that all economic agents make correct forecasts on average","The theory that economic agents form expectations using all available information efficiently \u2014 implying anticipated monetary or fiscal policy will be fully anticipated and priced in, making systematic demand management ineffective. Only surprise policy affects real variables","The theory that markets are always in equilibrium and policy has no effect","The theory that inflation expectations are always anchored at the central bank's target"],"a":1,"e":"Rational expectations (Lucas, Sargent, 1970s): if agents use all available information to forecast policy, anticipated stimulus will be neutralised \u2014 people will raise prices and wages in anticipation of stimulus. Only unanticipated policy surprises affect real variables. This challenged Keynesian demand management, led to the 'policy ineffectiveness proposition', and reinforced the importance of central bank credibility and rule-based policy frameworks. It underpins modern DSGE macroeconomic models.","cat":"MACRO","diff":"MD","mod":"Economic thought","concept":"Rational expectations"},{"q":"What is 'supply-side economics' and what were its key policy prescriptions?","o":["Economics focused exclusively on aggregate demand stimulation","The view that the primary lever for growth is expanding the productive capacity of the economy \u2014 through tax cuts (particularly on capital and high earners to incentivise investment), deregulation, and flexible labour markets. Associated with Reagan and Thatcher administrations of the 1980s","The theory that government supply of public goods drives economic growth","The view that only monetary policy can sustainably increase economic output"],"a":1,"e":"Supply-side economics (1980s): focus on expanding potential GDP rather than managing demand. Key policies: Reagan's 1981 income tax cuts (top rate 70% to 28%), capital gains tax cuts, deregulation (banking, airlines, telecoms), union reform (Thatcher). The 'Laffer Curve' suggested tax cuts would partly pay for themselves via higher growth. Results: US recovered from stagflation, but income inequality rose significantly. Supply-side ideas remain influential in fiscal policy debates about corporate tax rates and investment incentives.","cat":"MACRO","diff":"VP","mod":"Economic thought","concept":"Supply-side economics"}]

