/* ─── CACHE ─── */
const CACHE_TTL=4*60*60*1000;
const liveCache={};
function cacheKey(cat,diff){return `${cat}_${diff}`;}
function isCacheValid(key){const c=liveCache[key];return c&&c.questions&&c.questions.length>=4&&(Date.now()-c.ts)<CACHE_TTL;}

/* ─── STATIC QUIZ ─── */
app.post('/api/static-quiz',(req,res)=>{
  const{category='ALL',difficulty='ALL',module:mod='ALL',count=10,daily=false}=req.body||{};
  const limit=Math.max(4,Math.min(20,parseInt(count,10)||10));
  let pool=STATIC_Q;
  if(category!=='ALL')pool=pool.filter(q=>q.cat===category);
  if(difficulty!=='ALL')pool=pool.filter(q=>q.diff===difficulty);
  if(mod!=='ALL')pool=pool.filter(q=>q.mod===mod);
  if(pool.length<4)return res.status(400).json({error:`Only ${pool.length} question(s) match. Please broaden your filters.`});
  const seedStr=daily?new Date().toISOString().slice(0,10)+category+difficulty+mod:'';
  let seed=seedStr.split('').reduce((a,c)=>((a*31+c.charCodeAt(0))>>>0),2166136261);
  const rnd=()=>{seed=(seed*1664525+1013904223)>>>0;return seed/4294967296;};
  // Double-pass Fisher-Yates for variety
  const arr=[...pool];
  for(let i=arr.length-1;i>0;i--){const j=daily?Math.floor(rnd()*(i+1)):Math.floor(Math.random()*(i+1));[arr[i],arr[j]]=[arr[j],arr[i]];}
  if(!daily){for(let i=arr.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[arr[i],arr[j]]=[arr[j],arr[i]];}}
  const shuffled=arr;
  const selected=shuffled.slice(0,Math.min(limit,shuffled.length));
  const questions=selected.map(q=>{
    const correct=q.o[q.a];
    const opts=[...q.o].sort(()=>Math.random()-0.5);
    return{question:q.q,options:opts,answer:opts.indexOf(correct),explanation:q.e,category:q.cat,source:`Library — ${q.mod}`,headline:q.concept,mod:q.mod};
  });
  res.json({questions,total:pool.length,mode:'static'});
});

app.get('/api/static-stats',(req,res)=>{
  const stats={total:STATIC_Q.length,byCategory:{},byDifficulty:{},modules:[]};
  STATIC_Q.forEach(q=>{stats.byCategory[q.cat]=(stats.byCategory[q.cat]||0)+1;stats.byDifficulty[q.diff]=(stats.byDifficulty[q.diff]||0)+1;if(!stats.modules.includes(q.mod))stats.modules.push(q.mod);});
  stats.modules.sort();
  res.json(stats);
});

/* ─── TRANSLATION ─── */
app.post('/api/translate',async(req,res)=>{
  const ANTHROPIC_API_KEY=process.env.ANTHROPIC_API_KEY;
  if(!ANTHROPIC_API_KEY)return res.status(500).json({error:'Missing API key.'});
  const{questions,language}=req.body||{};
  if(!questions||language==='EN')return res.json({questions});
  const langName={FR:'French',JP:'Japanese'}[language]||'French';
  try{
    const r=await fetch('https://api.anthropic.com/v1/messages',{method:'POST',headers:{'Content-Type':'application/json','x-api-key':ANTHROPIC_API_KEY,'anthropic-version':'2023-06-01'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4000,system:`You are a professional financial translator. Translate to ${langName}. Preserve all technical terms precisely. Keep JSON structure identical.`,messages:[{role:'user',content:`Translate this quiz questions JSON array to ${langName}. Translate question, options, explanation and headline fields. Keep category, answer index, and source unchanged. Return ONLY the JSON array:
${JSON.stringify(questions)}`}]})});
    const data=await r.json();
    const text=(data.content||[]).filter(b=>b.type==='text').map(b=>b.text).join('');
    const clean=text.replace(/\`\`\`json|\`\`\`/g,'').trim();
    const start=clean.indexOf('['),end=clean.lastIndexOf(']');
    if(start===-1||end===-1)throw new Error('Translation parsing failed');
    const translated=JSON.parse(clean.slice(start,end+1));
    res.json({questions:translated});
  }catch(e){res.json({questions});}// fallback to original
});

/* ─── LIVE QUIZ GENERATION ─── */
async function generateQuestions(category,difficulty,count=10){
  const ANTHROPIC_API_KEY=process.env.ANTHROPIC_API_KEY;
  if(!ANTHROPIC_API_KEY)throw new Error('Missing ANTHROPIC_API_KEY.');
  const total=Math.max(5,Math.min(20,parseInt(count,10)||10));
  const diffNote={ANALYST:'conceptual — directional logic, definitions, basic mechanisms.',VP:'specific — named instruments, exact moves, causal chains.',MD:'expert — cross-asset, multi-factor, relative value.'}[difficulty]||'specific';
  const catNote=category==='ALL'?'balanced across Macro, FX, Rates, Equity and Commodities':`all questions on ${category}`;
  const date=new Date().toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'});
  const month=new Date().toLocaleDateString('en-GB',{month:'long',year:'numeric'});
  const chartPool=[...CHARTS].sort(()=>Math.random()-0.5).slice(0,3);
  const chartInstr=chartPool.map((c,i)=>`CHART Q${i+1}: "${c.title}" — ${c.period}\nData: ${c.xLabels.map((x,j)=>`${x}:${c.yValues[j]}`).join(', ')}\nContext: ${c.context}\nAsk about: ${c.question_angle}\nSet chart_id to "${c.id}"`).join('\n');
  const qTypes=['instrument mechanics','policy divergence and market impact','cross-asset correlation','macro regime identification','tail risk scenario','relative value vs history','positioning and flows','central-bank reaction function','market microstructure','historical analogue','portfolio construction','risk management'].sort(()=>Math.random()-0.5).slice(0,Math.max(2,total-3));
  const r=await fetch('https://api.anthropic.com/v1/messages',{method:'POST',headers:{'Content-Type':'application/json','x-api-key':ANTHROPIC_API_KEY,'anthropic-version':'2023-06-01'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:Math.min(8000,2200+total*330),system:`Market quiz generator for senior finance professionals. Today: ${month}. Accuracy first. Real mechanisms and events only.`,messages:[{role:'user',content:`Generate exactly ${total} quiz questions. ${catNote}. Difficulty: ${diffNote}.\nUse up to 3 CHART questions:\n${chartInstr}\nREGULAR question angles:\n${qTypes.map((t,i)=>`Q${i+1}: ${t}`).join('\n')}\nRules: real mechanisms only, all 4 options plausible, vary structure.\nReturn ONLY a JSON array:\n[{"question":"...","options":["...","...","...","..."],"answer":0,"explanation":"2-3 sentences","category":"MACRO|FX|RATES|EQUITY|COMMODITIES","source":"Market Intelligence, ${date}","headline":"concept or event","chart_id":null}]`}]})});
  if(!r.ok){const e=await r.text();let m=`API error ${r.status}`;try{m=JSON.parse(e).error?.message||m;}catch(_){}throw new Error(m);}
  const data=await r.json();
  const text=(data.content||[]).filter(b=>b.type==='text').map(b=>b.text).join('');
  const clean=text.replace(/\`\`\`json|\`\`\`/g,'').trim();
  const start=clean.indexOf('['),end=clean.lastIndexOf(']');
  if(start===-1||end===-1)throw new Error('Could not parse questions. Please retry.');
  const questions=JSON.parse(clean.slice(start,end+1));
  if(!Array.isArray(questions)||questions.length<4)throw new Error('Not enough questions returned.');
  const chartMap=Object.fromEntries(CHARTS.map(c=>[c.id,c]));
  questions.forEach(q=>{
    if(q.chart_id&&chartMap[q.chart_id]){const c=chartMap[q.chart_id];q.chart={title:c.title,period:c.period,yLabel:c.yLabel,xLabels:c.xLabels,yValues:c.yValues};}
    delete q.chart_id;
    // Shuffle options so correct answer is randomised
    const correct=q.options[q.answer];
    q.options=[...q.options].sort(()=>Math.random()-0.5);
    q.answer=q.options.indexOf(correct);
  });
  return questions;
}

async function generateAndCache(cat,diff){
  try{const qs=await generateQuestions(cat,diff);if(qs&&qs.length>=4){liveCache[cacheKey(cat,diff)]={questions:qs,ts:Date.now()};console.log(`[Cache] ✓ ${cat}/${diff}`);}}catch(e){console.log(`[Cache] ✗ ${cat}/${diff}: ${e.message}`);}
}

app.post('/api/quiz',async(req,res)=>{
  const ANTHROPIC_API_KEY=process.env.ANTHROPIC_API_KEY;
  if(!ANTHROPIC_API_KEY)return res.status(500).json({error:'Live AI mode needs ANTHROPIC_API_KEY set on the server. Library mode works without it.'});
  const{category='ALL',difficulty='VP',count=10}=req.body||{};
  const key=cacheKey(category,`${difficulty}_${count}`);
  if(isCacheValid(key)){const shuffled=[...liveCache[key].questions].sort(()=>Math.random()-0.5);if((Date.now()-liveCache[key].ts)>CACHE_TTL*0.75)setTimeout(()=>generateAndCache(category,difficulty),100);return res.json({questions:shuffled,cached:true});}
  try{const questions=await generateQuestions(category,difficulty,count);liveCache[key]={questions,ts:Date.now()};res.json({questions:[...questions].sort(()=>Math.random()-0.5),cached:false});setTimeout(()=>generateAndCache(category,difficulty),1000);}catch(e){res.status(500).json({error:e.message||'Unknown error.'});}
});

/* ─── CUSTOM QUIZ SESSIONS ─── */
const customSessions=new Map();
const CUSTOM_SESSION_TTL=24*60*60*1000;
function normaliseGeneratedQuestions(qs){
  if(!Array.isArray(qs))throw new Error('Generator did not return a question array.');
  return qs.slice(0,20).map((q,i)=>{
    if(!q.question||!Array.isArray(q.options)||q.options.length!==4)throw new Error(`Question ${i+1} is malformed.`);
    const answer=Number.isInteger(q.answer)?q.answer:0;
    return{
      question:String(q.question),
      options:q.options.map(String),
      answer:Math.max(0,Math.min(3,answer)),
      explanation:String(q.explanation||'Review the source text for the supporting context.'),
      category:String(q.category||'CUSTOM').toUpperCase(),
      source:'Custom text',
      headline:String(q.headline||'Custom concept')
    };
  });
}
async function generateCustomQuestions(text,language){
  const ANTHROPIC_API_KEY=process.env.ANTHROPIC_API_KEY;
  if(!ANTHROPIC_API_KEY)throw new Error('Custom quiz generation needs ANTHROPIC_API_KEY set on the server.');
  const langName={FR:'French',JP:'Japanese',EN:'English'}[language]||'English';
  const clipped=text.slice(0,18000);
  const r=await fetch('https://api.anthropic.com/v1/messages',{method:'POST',headers:{'Content-Type':'application/json','x-api-key':ANTHROPIC_API_KEY,'anthropic-version':'2023-06-01'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:7200,system:`Create rigorous finance quiz questions in ${langName}. Return valid JSON only.`,messages:[{role:'user',content:`From the source text below, generate exactly 20 multiple-choice quiz questions for market/finance training.\nRules:\n- 4 plausible options per question\n- answer is the zero-based index of the correct option\n- concise but useful explanation\n- category should be MACRO, FX, RATES, EQUITY, COMMODITIES, or CUSTOM\n- source must be "Custom text"\n- headline should name the concept being tested\nReturn ONLY a JSON array shaped like:\n[{"question":"...","options":["...","...","...","..."],"answer":0,"explanation":"...","category":"CUSTOM","source":"Custom text","headline":"..."}]\n\nSOURCE TEXT:\n${clipped}`}]})});
  if(!r.ok){const e=await r.text();let m=`API error ${r.status}`;try{m=JSON.parse(e).error?.message||m;}catch(_){}throw new Error(m);}
  const data=await r.json();
  const out=(data.content||[]).filter(b=>b.type==='text').map(b=>b.text).join('');
  const clean=out.replace(/\`\`\`json|\`\`\`/g,'').trim();
  const start=clean.indexOf('['),end=clean.lastIndexOf(']');
  if(start===-1||end===-1)throw new Error('Could not parse generated questions.');
  return normaliseGeneratedQuestions(JSON.parse(clean.slice(start,end+1)));
}
function pruneCustomSessions(){
  const now=Date.now();
  for(const[id,s]of customSessions.entries())if(now-s.createdAt>CUSTOM_SESSION_TTL)customSessions.delete(id);
}
app.post('/api/custom-quiz',async(req,res)=>{
  const{text='',language='EN'}=req.body||{};
  if(String(text).trim().length<200)return res.status(400).json({error:'Paste at least 200 characters of source text.'});
  try{
    pruneCustomSessions();
    const questions=await generateCustomQuestions(String(text),language);
    const sessionId=randomUUID().slice(0,8);
    const title=String(text).trim().split(/\n+/)[0].slice(0,90)||'Custom quiz session';
    customSessions.set(sessionId,{questions,title,createdAt:Date.now()});
    res.json({sessionId,title,questions});
  }catch(e){res.status(500).json({error:e.message||'Custom quiz generation failed.'});}
});
app.get('/api/session/:id',(req,res)=>{
  pruneCustomSessions();
  const session=customSessions.get(req.params.id);
  if(!session)return res.status(404).json({error:'Session not found or expired. Custom quiz links last 24 hours while this server is running.'});
  res.json({title:session.title,questions:session.questions});
});


