/* ══════════════════════════
   URL PARAMS — share quiz settings
   Usage: ?cat=FX&diff=VP&lang=JP&mod=FX+carry
   Or:    ?session=ABC123 (custom quiz)
══════════════════════════ */
function readUrlParams(){
  const params=new URLSearchParams(window.location.search);
  const session=params.get('session');
  if(session){loadSharedSession(session);return;}
  const cat=params.get('cat'),diff=params.get('diff'),lang=params.get('lang'),mod=params.get('mod'),mode=params.get('mode');
  // Apply settings directly without DOM query complications
  if(cat&&['ALL','MACRO','FX','RATES','EQUITY','COMMODITIES'].includes(cat)){
    selectedCat=cat;
    document.querySelectorAll('#catRow .chip').forEach(c=>c.classList.remove('active'));
    const match=[...document.querySelectorAll('#catRow .chip')].find(c=>c.getAttribute('onclick').includes("'"+cat+"'"));
    if(match)match.classList.add('active');
  }
  if(diff&&['ANALYST','VP','MD','ALL'].includes(diff)){
    selectedDiff=diff;
    document.querySelectorAll('[onclick*="selectDiff"]').forEach(c=>c.classList.remove('active'));
    const match=[...document.querySelectorAll('[onclick*="selectDiff"]')].find(c=>c.getAttribute('onclick').includes("'"+diff+"'"));
    if(match)match.classList.add('active');
    updateHeader();
  }
  if(lang&&['EN','FR','JP'].includes(lang)){
    selectedLang=lang;
    document.querySelectorAll('[onclick*="selectLang"]').forEach(c=>c.classList.remove('active'));
    const match=[...document.querySelectorAll('[onclick*="selectLang"]')].find(c=>c.getAttribute('onclick').includes("'"+lang+"'"));
    if(match)match.classList.add('active');
    updateHeader();
  }
  if(mod){
    const modClean=mod.replace(/[+]/g,' ');
    selectedMod=modClean;
    document.querySelectorAll('.mod-chips .chip').forEach(c=>c.classList.remove('active'));
    const match=[...document.querySelectorAll('.mod-chips .chip')].find(c=>{const oc=c.getAttribute('onclick');return oc&&oc.includes(modClean);});
    if(match)match.classList.add('active');
  }
  if(mode==='live')setMode('live');
}


function getShareUrl(){
  const base=window.location.origin+window.location.pathname;
  const params=new URLSearchParams();
  if(selectedCat!=='ALL')params.set('cat',selectedCat);
  if(selectedDiff!=='VP')params.set('diff',selectedDiff);
  if(selectedLang!=='EN')params.set('lang',selectedLang);
  if(selectedMod!=='ALL')params.set('mod',selectedMod);
  if(selectedMode==='live')params.set('mode','live');
  const qs=params.toString();
  return qs?base+'?'+qs:base;
}

async function loadSharedSession(sessionId){
  try{
    const res=await fetch('/api/session/'+sessionId);
    if(!res.ok)throw new Error('Session not found or expired');
    const data=await res.json();
    if(data.questions&&data.questions.length>=4){
      const banner=document.getElementById('sharedBanner');
      banner.style.display='flex';
      banner.innerHTML='<div class="shared-banner"><span class="shared-banner-label mono">CUSTOM QUIZ</span><span class="shared-banner-title">'+safe(data.title||'Shared quiz session')+'</span></div>';
      // Auto-start with shared questions
      questions=data.questions.slice(0,selectedLength);currentQ=0;score=0;answers=[];sessionStreak=0;maxSessionStreak=0;
      selectedMode='custom';
      renderQuestion();showScreen('screenQuiz');
    }
  }catch(e){showError('Shared quiz unavailable',e.message||'The shared quiz could not be loaded.');}
}

